                                            <span className="font-bold text-sm">{user.name}</span>
                                        </div>
                                    </div>

                                    {isFriend ? (
                                        <span className="text-xs text-[#777] font-medium">Friends</span>
                                    ) : status === 'sent' ? (
                                        <span className="text-xs text-[#1DB954] font-medium flex items-center gap-1"><Check size={12}/> Sent</span>
                                    ) : (
                                        <button 
                                            onClick={() => handleSendRequest(user.email)}
                                            className="px-3 py-1.5 bg-white text-black text-xs font-bold rounded-full hover:scale-105 transition-transform flex items-center gap-1"
                                        >
                                            <UserPlus size={14} /> Add
                                        </button>
                                    )}
                                </div>
                            );
                        })}
                        {query && searchResults.length === 0 && !isSearching && (
                            <div className="text-center text-[#555] text-sm py-4">No users found.</div>
                        )}
                    </div>
                </div>
            </div>
        )}

        <div className="md:hidden">
             <ChatWindow />
        </div>
    </div>
  );
};

import { User, FriendRequest, ChatMessage } from '../types';
import { auth, db } from './firebase';
import { 
  createUserWithEmailAndPassword, 
  signInWithEmailAndPassword, 
  signOut 
} from 'firebase/auth';
import { 
  doc, 
  setDoc, 
  getDoc, 
  updateDoc, 
  collection, 
  query, 
  where, 
  getDocs,
  onSnapshot
} from 'firebase/firestore';

// Helper to remove undefined values which Firestore hates
const cleanData = (obj: any) => {
  return JSON.parse(JSON.stringify(obj));
};

export const authService = {

  // 1. SIGN UP
  signup: async (name: string, email: string, password: string): Promise<User> => {
    try {
      const userCredential = await createUserWithEmailAndPassword(auth, email, password);
      const uid = userCredential.user.uid;

      const newUser: User = {
        name,
        email,
        image: '',
        friends: [],
        friendRequests: [],
        playlists: [],
      };

      await setDoc(doc(db, "users", uid), cleanData({
        ...newUser,
        likedSongs: [],
        history: [],
        chats: {},
        settings: { volume: 1 },
        currentActivity: { status: 'online', timestamp: Date.now() }
      }));

      return {
        ...newUser,
        // @ts-ignore 
        likedSongs: [],
        history: [],
        chats: {}
      };

    } catch (error: any) {
      if (error.code === 'auth/email-already-in-use') {
        throw new Error('User already exists.');
      }
      throw new Error(error.message || 'Signup failed');
    }
  },

  // 2. LOGIN
  login: async (email: string, password: string): Promise<User & { chats?: any, likedSongs?: any[], history?: any[] }> => {
    try {
      const userCredential = await signInWithEmailAndPassword(auth, email, password);
      const uid = userCredential.user.uid;

      // Set status to online immediately
      await updateDoc(doc(db, "users", uid), {
        "currentActivity.status": "online",
        "currentActivity.timestamp": Date.now()
      });

      const userDocRef = doc(db, "users", uid);
      const userDoc = await getDoc(userDocRef);

      if (!userDoc.exists()) {
        throw new Error("User data not found");
      }

      const userData = userDoc.data();

      return {
        email: userData.email,
        name: userData.name,
        image: userData.image,
        friends: userData.friends || [],
        friendRequests: userData.friendRequests || [],
        playlists: userData.playlists || [],
        likedSongs: userData.likedSongs || [],
        history: userData.history || [],
        chats: userData.chats || {},
        currentActivity: userData.currentActivity
      };

    } catch (error: any) {
      if (
        error.code === 'auth/invalid-credential' || 
        error.code === 'auth/user-not-found' || 
        error.code === 'auth/wrong-password' ||
        error.code === 'auth/invalid-email'
      ) {
        throw new Error("Password or Email Incorrect");
      }
      throw error;
    }
  },

  // --- REALTIME LISTENERS ---

  // Listen to MY user document
  subscribeToUserData: (callback: (data: any) => void) => {
    if (!auth.currentUser) return () => {};

    const userRef = doc(db, "users", auth.currentUser.uid);
    return onSnapshot(userRef, (doc) => {
      if (doc.exists()) {
        callback(doc.data());
      }
    });
  },

  // Listen to FRIENDS (Online Status, Song)
  subscribeToFriendsActivity: (friendEmails: string[], callback: (friendsData: any[]) => void) => {
    if (!friendEmails || friendEmails.length === 0) {
      callback([]);
      return () => {};
    }

    // Firestore 'in' query supports max 10. 
    // We slice to 10 for safety in this demo.
    const usersRef = collection(db, "users");
    const safeEmails = friendEmails.slice(0, 10); 

    const q = query(usersRef, where("email", "in", safeEmails));

    return onSnapshot(q, (snapshot) => {
      const friendsData = snapshot.docs.map(d => d.data());
      callback(friendsData);
    });
  },

  // --- ACTIONS ---

  sendChatMessage: async (senderEmail: string, receiverEmail: string, message: ChatMessage) => {
    if (!auth.currentUser) return;

    // 1. Update Me
    const myRef = doc(db, "users", auth.currentUser.uid);

    // Clean payload
    const safeMessage = cleanData(message);

    try {
        const myDoc = await getDoc(myRef);
        if (myDoc.exists()) {
            const myData = myDoc.data();
            const myChats = myData.chats || {};
            const chatWithReceiver = myChats[receiverEmail] || [];

            await updateDoc(myRef, {
                [`chats.${receiverEmail.replace(/\./g, '_dot_')}`]: [...chatWithReceiver, safeMessage]
            }).catch(async () => {
                 // Fallback if dot notation fails due to email structure, try standard map update (less atomic but works)
                 // Or we accept that we must sanitize email keys. 
                 // For now, let's use the standard update assuming valid keys or handle mapping in store.
                 // Actually, simpler: Just overwrite the whole chats object for this friend if dot notation fails
                 myChats[receiverEmail] = [...chatWithReceiver, safeMessage];
                 await updateDoc(myRef, { chats: myChats });
            });
        }

        // 2. Update Friend
        const usersRef = collection(db, "users");
        const q = query(usersRef, where("email", "==", receiverEmail));
        const querySnapshot = await getDocs(q);

        if (!querySnapshot.empty) {
            const friendDoc = querySnapshot.docs[0];
            const friendData = friendDoc.data();
            const friendChats = friendData.chats || {};
            const chatWithSender = friendChats[senderEmail] || [];

            const updatedFriendChats = {
                ...friendChats,
                [senderEmail]: [...chatWithSender, safeMessage]
            };

            await updateDoc(friendDoc.ref, {
                chats: updatedFriendChats
            });
        }
    } catch (e) {
        console.error("Failed to send message", e);
        throw e;
    }
  },

  updateUserStatus: async (status: 'online' | 'offline' | 'listening', song?: any) => {
     if (!auth.currentUser) return;
     const userRef = doc(db, "users", auth.currentUser.uid);

     const activity = cleanData({
         status,
         timestamp: Date.now(),
         song: song || null
     });

     await updateDoc(userRef, {
         currentActivity: activity
     });
  },

  syncPublicProfile: async (user: User, chats?: Record<string, ChatMessage[]>) => {
    if (!auth.currentUser) return;
    const userRef = doc(db, "users", auth.currentUser.uid);
    const updates: any = {
      name: user.name,
      image: user.image,
      friends: user.friends,
      friendRequests: user.friendRequests,
      playlists: user.playlists 
    };
    if (chats) updates.chats = chats;
    await updateDoc(userRef, cleanData(updates));
  },

  syncPrivateData: async (user: User, additionalData: any) => {
     if (!auth.currentUser) return;
     const userRef = doc(db, "users", auth.currentUser.uid);
     await updateDoc(userRef, cleanData({
         playlists: user.playlists, 
         likedSongs: additionalData.likedSongs,
         history: additionalData.history
     }));
  },

  searchUsers: async (queryText: string) => {
      const usersRef = collection(db, "users");
      const q = query(usersRef); 
      const querySnapshot = await getDocs(q);
      const results: any[] = [];
      const lowerQ = queryText.toLowerCase();

      querySnapshot.forEach((doc) => {
          const data = doc.data();
          if (
              (data.name && data.name.toLowerCase().includes(lowerQ)) || 
              (data.email && data.email.toLowerCase().includes(lowerQ))
          ) {
              results.push({
                  name: data.name,
                  email: data.email,
                  image: data.image
              });
          }
      });
      return results.slice(0, 10);
  },

  sendFriendRequest: async (toEmail: string, fromUser: User) => {
      const usersRef = collection(db, "users");
      const q = query(usersRef, where("email", "==", toEmail));
      const querySnapshot = await getDocs(q);

      if (querySnapshot.empty) throw new Error("User not found");

      const targetDoc = querySnapshot.docs[0];
      const targetData = targetDoc.data();
      const currentRequests: FriendRequest[] = targetData.friendRequests || [];
      const currentFriends: string[] = targetData.friends || [];

      if (currentFriends.includes(fromUser.email)) throw new Error("Already friends");
      if (currentRequests.find((r) => r.fromEmail === fromUser.email)) throw new Error("Request already sent");

      // Critical: Clean undefined values before sending to Firestore
      const newRequest = cleanData({
          fromEmail: fromUser.email,
          fromName: fromUser.name || 'Unknown',
          fromImage: fromUser.image || '',
          timestamp: Date.now()
      });

      await updateDoc(targetDoc.ref, {
          friendRequests: [...currentRequests, newRequest]
      });
  },

  acceptFriendRequest: async (requestFromEmail: string, currentUser: User) => {
      if (!auth.currentUser) throw new Error("Not authenticated");
      const myRef = doc(db, "users", auth.currentUser.uid);

      // Update Sender
      const usersRef = collection(db, "users");
      const q = query(usersRef, where("email", "==", requestFromEmail));
      const senderSnapshot = await getDocs(q);

      if (!senderSnapshot.empty) {
          const senderDoc = senderSnapshot.docs[0];
          const senderData = senderDoc.data();
          const senderFriends = senderData.friends || [];
          if (!senderFriends.includes(currentUser.email)) {
             await updateDoc(senderDoc.ref, { friends: [...senderFriends, currentUser.email] });
          }
      }

      // Update Me
      const myDoc = await getDoc(myRef);
      if (myDoc.exists()) {
          const data = myDoc.data();
          const currentRequests = data.friendRequests || [];
          const currentFriends = data.friends || [];
          const newRequests = currentRequests.filter((r: any) => r.fromEmail !== requestFromEmail);
          const newFriends = [...currentFriends];
          if (!newFriends.includes(requestFromEmail)) newFriends.push(requestFromEmail);

          await updateDoc(myRef, {
              friendRequests: newRequests,
              friends: newFriends
          });
          return { ...currentUser, friendRequests: newRequests, friends: newFriends };
      }
      return currentUser;
  },

  logout: async () => {
      if (auth.currentUser) {
           const userRef = doc(db, "users", auth.currentUser.uid);
           await updateDoc(userRef, { "currentActivity.status": "offline" }).catch(console.error);
      }
      await signOut(auth);
  }
};

import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import { Song, UserPlaylist, User, Friend, ChatMessage, PartySession, FriendRequest } from '../types';
import { authService } from '../services/auth';

interface PlayerState {
  isPlaying: boolean;
  isBuffering: boolean;
  isFullScreen: boolean;
  currentSong: Song | null;
  queue: Song[];
  history: Song[];
  likedSongs: Song[];
  userPlaylists: UserPlaylist[];
  volume: number;
  isShuffling: boolean;

  // Auth
  currentUser: User | null;

  // Social
  friends: Friend[]; // Unified list
  friendRequests: FriendRequest[];
  searchResults: { name: string, email: string, image?: string }[];
  activeChatFriendId: string | null;
  partySession: PartySession | null;

  // Realtime Cleanup
  unsubscribers: Function[];

  // Actions
  playSong: (song: Song, newQueue?: Song[]) => void;
  togglePlay: () => void;
  setIsPlaying: (isPlaying: boolean) => void;
  setIsBuffering: (isBuffering: boolean) => void;
  setFullScreen: (isFull: boolean) => void;
  nextSong: () => void;
  prevSong: () => void;
  addToQueue: (song: Song) => void;
  setQueue: (songs: Song[]) => void;
  setVolume: (val: number) => void;
  addToHistory: (song: Song) => void;
  toggleLike: (song: Song) => void;
  createPlaylist: (playlist: UserPlaylist) => void;
  addSongToPlaylist: (playlistId: string, song: Song) => void;
  removePlaylist: (id: string) => void;

  // Auth Actions
  loginUser: (user: User & { likedSongs?: Song[], history?: Song[], chats?: any }) => void;
  logoutUser: () => void;
  syncUserToCloud: (type?: 'public' | 'private' | 'both') => void;
  updateUserProfile: (name: string, image?: string) => void;
  initRealtimeListeners: () => void;

  // Social Actions
  searchUsers: (query: string) => Promise<void>;
  sendFriendRequest: (toEmail: string) => Promise<void>;
  acceptFriendRequest: (fromEmail: string) => Promise<void>;
  refreshFriendsActivity: () => Promise<void>;
  openChat: (friendId: string | null) => void;
  sendMessage: (friendId: string, text: string) => void;
  startParty: () => void;
  stopParty: () => void;
}

export const usePlayerStore = create<PlayerState>()(
  persist(
    (set, get) => ({
      isPlaying: false,
      isBuffering: false,
      isFullScreen: false,
      currentSong: null,
      queue: [],
      history: [],
      likedSongs: [],
      userPlaylists: [],
      volume: 1,
      isShuffling: false,
      currentUser: null,

      // Social Initial State
      friends: [],
      friendRequests: [],
      searchResults: [],
      activeChatFriendId: null,
      partySession: null,
      unsubscribers: [],

      playSong: (song, newQueue) => {
        const { addToHistory, currentUser } = get();
        addToHistory(song);

        if (currentUser) {
            authService.updateUserStatus('listening', song);
        }

        set((state) => ({
          currentSong: song,
          isPlaying: true,
          isBuffering: true, 
          queue: newQueue ? newQueue : state.queue,
          isFullScreen: true,
        }));
      },

      togglePlay: () => set((state) => ({ isPlaying: !state.isPlaying })),

      setIsPlaying: (isPlaying) => {
          set({ isPlaying });
          const { currentUser, currentSong } = get();
          if (currentUser && !isPlaying) {
             authService.updateUserStatus('online', currentSong);
          }
      },

      setIsBuffering: (isBuffering) => set({ isBuffering }),
      setFullScreen: (isFullScreen) => set({ isFullScreen }),

      nextSong: () => {
        const { queue, currentSong, isShuffling } = get();
        if (!currentSong) return;
        const currentIndex = queue.findIndex(s => s.id === currentSong.id);
        let nextIndex = isShuffling ? Math.floor(Math.random() * queue.length) : currentIndex + 1;
        if (nextIndex < queue.length) get().playSong(queue[nextIndex]);
        else set({ isPlaying: false });
      },

      prevSong: () => {
        const { queue, currentSong } = get();
        if (!currentSong) return;
        const currentIndex = queue.findIndex(s => s.id === currentSong.id);
        if (currentIndex - 1 >= 0) get().playSong(queue[currentIndex - 1]);
      },

      addToQueue: (song) => set((state) => ({ queue: [...state.queue, song] })),
      setQueue: (songs) => set({ queue: songs }),
      setVolume: (volume) => set({ volume }),

      addToHistory: (song) => {
          set((state) => {
            const newHistory = [song, ...state.history.filter(s => s.id !== song.id)].slice(0, 20);
            setTimeout(() => get().syncUserToCloud('private'), 1000);
            return { history: newHistory };
          });
      },

      toggleLike: (song) => {
          set((state) => {
            const isLiked = state.likedSongs.some(s => s.id === song.id);
            const newLiked = isLiked ? state.likedSongs.filter(s => s.id !== song.id) : [song, ...state.likedSongs];
            setTimeout(() => get().syncUserToCloud('private'), 1000);
            return { likedSongs: newLiked };
          });
      },

      createPlaylist: (playlist) => {
        set((state) => {
           const newPlaylists = [playlist, ...state.userPlaylists];
           if (state.currentUser) {
             const updatedUser = { ...state.currentUser, playlists: newPlaylists };
             setTimeout(() => get().syncUserToCloud('private'), 1000);
             return { userPlaylists: newPlaylists, currentUser: updatedUser };
           }
           return { userPlaylists: newPlaylists };
        });
      },

      addSongToPlaylist: (playlistId, song) => {
        set((state) => {
          const newPlaylists = state.userPlaylists.map(p => {
            if (p.id === playlistId) {
               if (p.songs.some(s => s.id === song.id)) return p;
               return { ...p, songs: [...p.songs, song] };
            }
            return p;
          });
          if (state.currentUser) {
             const updatedUser = { ...state.currentUser, playlists: newPlaylists };
             setTimeout(() => get().syncUserToCloud('private'), 1000);
             return { userPlaylists: newPlaylists, currentUser: updatedUser };
           }
           return { userPlaylists: newPlaylists };
        });
      },

      removePlaylist: (id) => {
        set((state) => {
           const newPlaylists = state.userPlaylists.filter(p => p.id !== id);
           if (state.currentUser) {
             const updatedUser = { ...state.currentUser, playlists: newPlaylists };
             setTimeout(() => get().syncUserToCloud('private'), 1000);
             return { userPlaylists: newPlaylists, currentUser: updatedUser };
           }
           return { userPlaylists: newPlaylists };
        });
      },

      loginUser: (user) => {
          set({ 
            currentUser: user, 
            userPlaylists: user.playlists || [],
            likedSongs: user.likedSongs || [],
            history: user.history || [],
            friendRequests: user.friendRequests || []
          });
          get().initRealtimeListeners();
      },

      initRealtimeListeners: () => {
         const { unsubscribers, currentUser } = get();
         // Cleanup old listeners
         unsubscribers.forEach(unsub => unsub());

         if (!currentUser) {
             set({ unsubscribers: [] });
             return;
         }

         const newUnsubscribers: Function[] = [];

         // 1. Listen to MY DATA (Requests, Chats, Friend List changes)
         const unsubUser = authService.subscribeToUserData((data) => {
             set((state) => {
                 const updatedUser = { ...state.currentUser, ...data } as User;

                 // Merge Logic:
                 // We want to update 'friends' list if:
                 // a) A new friend was added (in data.friends)
                 // b) Chat history updated (in data.chats)
                 // But we want to PRESERVE status/song info from the other listener.

                 const existingFriends = state.friends;
                 const serverFriendEmails = data.friends || [];
                 const serverChats = data.chats || {};

                 // Reconstruct friends array based on server email list
                 const mergedFriends: Friend[] = serverFriendEmails.map((email: string) => {
                     // Find existing state for this friend to keep status/song
                     const existing = existingFriends.find(f => f.id === email);

                     // Get chats from my doc (source of truth for my view of chat)
                     const chatHistory = serverChats[email] || serverChats[email.replace(/\./g, '_dot_')] || [];

                     return {
                         id: email,
                         name: existing?.name || email.split('@')[0], // Fallback name
                         image: existing?.image || '',
                         status: existing?.status || 'offline', // Preserve status
                         currentSong: existing?.currentSong || null, // Preserve song
                         lastActive: existing?.lastActive || 0,
                         chatHistory: chatHistory
                     };
                 });

                 return {
                     currentUser: updatedUser,
                     friendRequests: data.friendRequests || [],
                     friends: mergedFriends,
                     userPlaylists: data.playlists || state.userPlaylists
                 };
             });

             // If friends list changed, we might need to re-subscribe to their activity
             // A simplified approach: trigger the 2nd listener again if list grows
             // For now, we assume initial load covers it, or reload app to sync new friend status
         });
         newUnsubscribers.push(unsubUser);

         // 2. Listen to FRIENDS ACTIVITY (Status, Song)
         if (currentUser.friends && currentUser.friends.length > 0) {
             const unsubFriends = authService.subscribeToFriendsActivity(currentUser.friends, (friendsData) => {
                 set((state) => {
                     // Update only status/song/image/name for existing friends
                     const updatedFriends = state.friends.map(f => {
                         const liveData = friendsData.find((d: any) => d.email === f.id);
                         if (liveData) {
                             return {
                                 ...f,
                                 name: liveData.name || f.name,
                                 image: liveData.image || f.image,
                                 status: liveData.currentActivity?.status || 'offline',
                                 currentSong: liveData.currentActivity?.song || null,
                                 lastActive: liveData.currentActivity?.timestamp || 0
                             };
                         }
                         return f;
                     });
                     return { friends: updatedFriends };
                 });
             });
             newUnsubscribers.push(unsubFriends);
         }

         set({ unsubscribers: newUnsubscribers });
      },

      logoutUser: async () => {
        get().unsubscribers.forEach(unsub => unsub());
        await authService.logout();
        set({ 
            currentUser: null, 
            userPlaylists: [],
            friends: [],
            friendRequests: [],
            partySession: null,
            likedSongs: [],
            history: [],
            unsubscribers: []
        });
      },

      syncUserToCloud: async (type = 'both') => {
         const { currentUser, userPlaylists, likedSongs, history } = get();
         if (!currentUser) return;
         const updatedUser = { ...currentUser, playlists: userPlaylists };
         try {
             if (type === 'public' || type === 'both') await authService.syncPublicProfile(updatedUser);
             if (type === 'private' || type === 'both') await authService.syncPrivateData(updatedUser, { likedSongs, history });
         } catch (e) {
             console.error("Sync failed", e);
         }
      },

      updateUserProfile: (name, image) => {
        set((state) => {
          if (!state.currentUser) return {};
          const updatedUser = { 
              ...state.currentUser, 
              name: name,
              image: image !== undefined ? image : state.currentUser.image 
          };
          setTimeout(() => get().syncUserToCloud('public'), 100);
          return { currentUser: updatedUser };
        });
      },

      searchUsers: async (query) => {
          try {
              const results = await authService.searchUsers(query);
              const { currentUser } = get();
              const filtered = results.filter(u => u.email !== currentUser?.email);
              set({ searchResults: filtered });
          } catch (e) { console.error(e); }
      },

      sendFriendRequest: async (toEmail) => {
          const { currentUser } = get();
          if (!currentUser) return;
          await authService.sendFriendRequest(toEmail, currentUser);
      },

      acceptFriendRequest: async (fromEmail) => {
          const { currentUser } = get();
          if (!currentUser) return;
          await authService.acceptFriendRequest(fromEmail, currentUser);
          setTimeout(() => get().initRealtimeListeners(), 1000);
      },

      refreshFriendsActivity: async () => {
          get().initRealtimeListeners();
      },

      openChat: (friendId) => set({ activeChatFriendId: friendId }),

      sendMessage: async (friendId, text) => {
          const { currentUser } = get();
          if (!currentUser) return;

          const newMessage: ChatMessage = {
              id: `msg-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
              senderId: currentUser.email,
              text,
              timestamp: Date.now()
          };

          // Optimistic update done via realtime listener on 'chats' usually, 
          // but we can do it here for instant feel if listener is slow
          set((state) => {
              const updatedFriends = state.friends.map(f => {
                  if (f.id === friendId) {
                      return { ...f, chatHistory: [...f.chatHistory, newMessage] };
                  }
                  return f;
              });
              return { friends: updatedFriends };
          });

          await authService.sendChatMessage(currentUser.email, friendId, newMessage);
      },

      startParty: () => set((state) => {
         if (!state.currentUser) return {};
         return {
             partySession: {
                 isActive: true,
                 hostId: 'me',
                 hostName: state.currentUser.name,
                 listeners: state.activeChatFriendId ? [state.activeChatFriendId] : []
             }
         }
      }),

      stopParty: () => set({ partySession: null })
    }),
    {
      name: 'vibestream-storage',
      partialize: (state) => ({ 
        history: state.history, 
        volume: state.volume,
        likedSongs: state.likedSongs,
        userPlaylists: state.userPlaylists,
        currentUser: state.currentUser,
      }), 
    }
  )
);

import React, { useState, useEffect, useRef } from 'react';
import { usePlayerStore } from '../store/playerStore';
import { X, Send, PlayCircle, StopCircle, Music, Radio, ChevronDown } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

export const ChatWindow: React.FC = () => {
  const { activeChatFriendId, friends, openChat, sendMessage, partySession, startParty, stopParty, currentUser } = usePlayerStore();
  const [text, setText] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const friend = friends.find(f => f.id === activeChatFriendId);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [friend?.chatHistory, activeChatFriendId]);

  if (!activeChatFriendId || !friend || !currentUser) return null;

  const handleSend = (e: React.FormEvent) => {
    e.preventDefault();
    if (text.trim()) {
        sendMessage(friend.id, text);
        setText('');
    }
  };

  const isHostingParty = partySession?.hostId === 'me' && partySession.isActive;

  const formatTime = (ts: number) => {
      return new Date(ts).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  return (
    <motion.div 
        initial={{ y: 20, opacity: 0, scale: 0.95 }}
        animate={{ y: 0, opacity: 1, scale: 1 }}
        exit={{ y: 20, opacity: 0 }}
        className="fixed bottom-24 right-4 w-[360px] h-[500px] bg-[#121212] rounded-2xl border border-[#282828] shadow-[0_8px_30px_rgba(0,0,0,0.5)] flex flex-col z-[100] overflow-hidden font-sans"
    >

        {/* Header */}
        <div className="bg-[#181818]/95 backdrop-blur-md p-3 flex items-center justify-between border-b border-[#282828]">
            <div className="flex items-center gap-3">
                <div className="relative">
                    <img src={friend.image || `https://ui-avatars.com/api/?name=${friend.name}&background=1DB954&color=fff`} className="w-10 h-10 rounded-full object-cover shadow-md" alt="" />
                    {friend.status === 'listening' ? (
                        <div className="absolute -bottom-0.5 -right-0.5 w-3.5 h-3.5 bg-[#1DB954] rounded-full border-2 border-[#121212] flex items-center justify-center">
                            <Music size={8} fill="black" className="text-black" />
                        </div>
                    ) : friend.status === 'online' ? (
                        <div className="absolute -bottom-0.5 -right-0.5 w-3.5 h-3.5 bg-green-500 rounded-full border-2 border-[#121212]"></div>
                    ) : null}
                </div>
                <div className="flex flex-col">
                    <span className="text-white font-bold text-sm leading-tight">{friend.name}</span>
                    {friend.status === 'listening' && friend.currentSong ? (
                        <span className="text-[11px] text-[#1DB954] flex items-center gap-1 font-medium truncate max-w-[150px]">
                            Listening to {friend.currentSong.name}
                        </span>
                    ) : (
                        <span className="text-[11px] text-[#777] font-medium">
                            {friend.status === 'online' ? 'Active Now' : 'Offline'}
                        </span>
                    )}
                </div>
            </div>
            <div className="flex items-center gap-1">
                 <button 
                    onClick={isHostingParty ? stopParty : startParty}
                    className={`p-2 rounded-full transition-all ${isHostingParty ? 'text-[#1DB954] bg-[#1DB954]/10' : 'text-[#B3B3B3] hover:text-white hover:bg-[#282828]'}`}
                    title="Listen Together"
                >
                    <Radio size={20} className={isHostingParty ? "animate-pulse" : ""} />
                 </button>
                 <button onClick={() => openChat(null)} className="p-2 text-[#B3B3B3] hover:text-white hover:bg-[#282828] rounded-full transition-colors">
                    <ChevronDown size={20} />
                </button>
            </div>
        </div>

        {/* Messages Area */}
        <div className="flex-1 overflow-y-auto p-4 flex flex-col gap-2 bg-[#000000] bg-opacity-40">
             <div className="text-[10px] text-center text-[#444] my-2 uppercase tracking-widest font-bold">
                 Encrypted Chat
             </div>

             {friend.chatHistory.map((msg, i) => {
                 const isMe = msg.senderId === currentUser.email;
                 const isConsecutive = i > 0 && friend.chatHistory[i-1].senderId === msg.senderId;

                 return (
                     <div key={msg.id} className={`flex flex-col ${isMe ? 'items-end' : 'items-start'} ${isConsecutive ? 'mt-0.5' : 'mt-2'}`}>
                         <div 
                            className={`max-w-[75%] px-3.5 py-2 text-[13px] shadow-sm leading-relaxed relative group ${
                                isMe 
                                ? 'bg-[#1DB954] text-black rounded-2xl rounded-tr-sm' 
                                : 'bg-[#2A2A2A] text-white rounded-2xl rounded-tl-sm'
                            }`}
                         >
                             {msg.text}
                             <div className={`text-[9px] mt-1 opacity-60 text-right ${isMe ? 'text-black' : 'text-gray-400'}`}>
                                 {formatTime(msg.timestamp)}
                             </div>
                         </div>
                     </div>
                 );
             })}
             <div ref={messagesEndRef} />
        </div>

        {/* Input Area */}
        <form onSubmit={handleSend} className="p-3 bg-[#181818] border-t border-[#282828] flex items-center gap-2">
            <input 
                value={text}
                onChange={(e) => setText(e.target.value)}
                placeholder="Type a message..."
                className="flex-1 bg-[#282828] rounded-full px-4 py-2.5 text-sm text-white focus:outline-none focus:ring-1 focus:ring-[#555] transition-all placeholder-[#555]"
            />
            <button 
                type="submit" 
                disabled={!text.trim()} 
                className="p-2.5 bg-[#1DB954] text-black rounded-full hover:scale-105 active:scale-95 disabled:opacity-50 disabled:scale-100 transition-all shadow-lg"
            >
                <Send size={18} fill="black" className="ml-0.5" />
            </button>
        </form>
    </motion.div>
  );
};

