import React, { useState } from 'react';
import { usePlayerStore } from '../store/playerStore';
import { ChatWindow } from '../components/ChatWindow';
import { UserPlus, Music2, ChevronRight, Search, Check, X, Loader2, User, UserCheck, MessageCircle } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

export const Social: React.FC = () => {
  const { friends, friendRequests, openChat, currentUser, searchUsers, searchResults, sendFriendRequest, acceptFriendRequest } = usePlayerStore();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState<'activity' | 'add'>('activity');
  const [query, setQuery] = useState('');
  const [isSearching, setIsSearching] = useState(false);
  const [requestStatus, setRequestStatus] = useState<{[email: string]: 'sent' | 'error' | null}>({});

  const handleSearch = async (val: string) => {
      setQuery(val);
      if (val.length > 2) {
          setIsSearching(true);
          await searchUsers(val);
          setIsSearching(false);
      }
  };

  const handleSendRequest = async (email: string) => {
      setRequestStatus(prev => ({...prev, [email]: null}));
      try {
          await sendFriendRequest(email);
          setRequestStatus(prev => ({...prev, [email]: 'sent'}));
      } catch (e) {
          setRequestStatus(prev => ({...prev, [email]: 'error'}));
      }
  };

  if (!currentUser) {
      return (
          <div className="flex flex-col items-center justify-center h-full p-8 text-center gap-4">
              <h2 className="text-xl font-bold text-white">Connect with Friends</h2>
              <p className="text-[#B3B3B3]">Log in to see what your friends are listening to and chat with them.</p>
              <button onClick={() => navigate('/login')} className="px-8 py-3 bg-white text-black font-bold rounded-full hover:scale-105 transition-transform">Log In</button>
          </div>
      );
  }

  return (
    <div className="min-h-full pb-32 bg-black px-4 pt-4">

        {/* Header Tabs */}
        <div className="flex items-center gap-6 mb-6 border-b border-[#282828]">
            <button 
                onClick={() => setActiveTab('activity')}
                className={`text-lg font-bold pb-3 border-b-2 transition-all flex items-center gap-2 ${activeTab === 'activity' ? 'text-white border-[#1DB954]' : 'text-[#B3B3B3] border-transparent hover:text-white'}`}
            >
                Friends
                {friendRequests.length > 0 && (
                    <span className="bg-[#1DB954] text-black text-[10px] w-5 h-5 flex items-center justify-center rounded-full font-bold shadow-sm">{friendRequests.length}</span>
                )}
            </button>
            <button 
                onClick={() => setActiveTab('add')}
                className={`text-lg font-bold pb-3 border-b-2 transition-all ${activeTab === 'add' ? 'text-white border-[#1DB954]' : 'text-[#B3B3B3] border-transparent hover:text-white'}`}
            >
                Add Friends
            </button>
        </div>

        {activeTab === 'activity' && (
            <div className="flex flex-col gap-4 max-w-2xl mx-auto">

                {/* --- PENDING REQUESTS --- */}
                {friendRequests.length > 0 && (
                    <div className="bg-[#181818] rounded-xl p-4 border border-[#333] mb-4 shadow-lg animate-in slide-in-from-top fade-in">
                        <h3 className="text-white font-bold mb-3 flex items-center gap-2 text-sm uppercase tracking-wider text-[#1DB954]">
                            <UserCheck size={16} />
                            Friend Requests
                        </h3>
                        <div className="flex flex-col gap-3">
                            {friendRequests.map((req, i) => (
                                <div key={i} className="flex items-center justify-between bg-[#121212] p-3 rounded-lg border border-white/5">
                                    <div className="flex items-center gap-3">
                                        <img src={req.fromImage || `https://ui-avatars.com/api/?name=${req.fromName}`} className="w-12 h-12 rounded-full object-cover" alt="" />
                                        <div className="flex flex-col">
                                            <span className="font-bold text-base text-white">{req.fromName}</span>
                                            <span className="text-xs text-[#777]">wants to connect</span>
                                        </div>
                                    </div>
                                    <div className="flex gap-3">
                                        <button onClick={() => acceptFriendRequest(req.fromEmail)} className="w-10 h-10 bg-[#1DB954] rounded-full flex items-center justify-center text-black hover:scale-105 active:scale-95 shadow-md transition-transform">
                                            <Check size={20} strokeWidth={3} />
                                        </button>
                                        <button className="w-10 h-10 bg-[#333] rounded-full flex items-center justify-center text-white hover:bg-[#444] active:scale-95 transition-colors">
                                            <X size={20} strokeWidth={3} />
                                        </button>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                )}

                {/* --- FRIENDS LIST --- */}
                {friends.length === 0 ? (
                    <div className="text-center text-[#777] mt-10 bg-[#181818] p-8 rounded-xl border border-[#282828]">
                        <UserPlus size={48} className="mx-auto mb-4 opacity-50" />
                        <p className="text-lg text-white font-bold">No friends yet</p>
                        <p className="text-sm mb-4">Add friends to see what they are listening to.</p>
                        <button onClick={() => setActiveTab('add')} className="px-6 py-2 bg-white text-black font-bold rounded-full hover:scale-105 transition-transform">Find Friends</button>
                    </div>
                ) : (
                    <div className="flex flex-col gap-2">
                        {friends.map((friend) => (
                            <div 
                                key={friend.id} 
                                className="flex items-center gap-4 p-4 bg-[#121212] rounded-xl hover:bg-[#1A1A1A] transition-colors cursor-pointer group border border-transparent hover:border-[#333]"
                                onClick={() => openChat(friend.id)}
                            >
                                <div className="relative">
                                    <img src={friend.image || `https://ui-avatars.com/api/?name=${friend.name}`} alt={friend.name} className="w-14 h-14 rounded-full object-cover shadow-lg" />
