                    </div>

                    <div className="flex flex-col gap-2">
                        {searchResults.map((user) => {
                            const isFriend = friends.some(f => f.id === user.email);
                            const status = requestStatus[user.email];

                            return (
                                <div key={user.email} className="flex items-center justify-between p-4 bg-[#121212] rounded-xl border border-white/5 hover:border-white/10 transition-colors">
                                    <div className="flex items-center gap-4">
                                        <img src={user.image || `https://ui-avatars.com/api/?name=${user.name}`} className="w-12 h-12 rounded-full object-cover" alt="" />
                                        <div className="flex flex-col">
                                            <span className="font-bold text-white text-base">{user.name}</span>
                                            <span className="text-xs text-[#555]">{user.email}</span>
                                        </div>
                                    </div>

                                    {isFriend ? (
                                        <span className="text-xs text-[#777] font-bold bg-[#222] px-3 py-1 rounded-full">Friends</span>
                                    ) : status === 'sent' ? (
                                        <span className="text-xs text-[#1DB954] font-bold flex items-center gap-1 bg-[#1DB954]/10 px-3 py-1 rounded-full"><Check size={12}/> Request Sent</span>
                                    ) : (
                                        <button 
                                            onClick={() => handleSendRequest(user.email)}
                                            className="px-4 py-2 bg-white text-black text-xs font-bold rounded-full hover:scale-105 transition-transform flex items-center gap-1 shadow-md"
                                        >
                                            <UserPlus size={14} /> Add Friend
                                        </button>
                                    )}
                                </div>
                            );
