            <div className="flex flex-col gap-6 max-w-2xl mx-auto">
                <div>
                     <div className="relative mb-6">
                        <Search size={20} className="absolute left-4 top-1/2 -translate-y-1/2 text-[#777]" />
                        <input 
                            type="text" 
                            value={query}
                            onChange={(e) => handleSearch(e.target.value)}
