import React from 'react';
import { Play } from 'lucide-react';
import { SearchResult } from '../types';
import { getImageUrl } from '../services/api';
import { useNavigate } from 'react-router-dom';

interface SongCardProps {
  item: SearchResult;
  onPlay?: () => void;
  subtitle?: string;
  round?: boolean;
}

export const SongCard: React.FC<SongCardProps> = ({ item, onPlay, subtitle, round = false }) => {
  const navigate = useNavigate();
  const imageUrl = getImageUrl(item.image);

  const handleClick = () => {
    if (item.type === 'album') {
      navigate(`/album/${item.id}`);
    } else if (item.type === 'artist') {
      navigate(`/artist/${item.id}`, { state: { artist: item } });
    } else if (item.type === 'song' && onPlay) {
      onPlay();
    }
  };

  const handlePlayClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (onPlay) onPlay();
  };

  // Safe subtitle generation
  let safeSubtitle = subtitle;
  if (!safeSubtitle) {
      if (item.type === 'song') {
          safeSubtitle = item.artists?.primary?.[0]?.name || item.artists?.all?.[0]?.name || 'Artist';
      } else if (item.type === 'album') {
          safeSubtitle = `Album • ${item.artists?.primary?.[0]?.name || 'Artist'}`;
      } else if (item.type === 'artist') {
          safeSubtitle = 'Artist';
      } else if (item.type === 'playlist') {
          safeSubtitle = item.subtitle || 'Playlist';
      }
  }

  // Handle display title (Playlist has 'title', others have 'name')
  const displayTitle = item.type === 'playlist' ? item.title : item.name;

  return (
    <div 
      onClick={handleClick}
      className="group relative bg-[#181818] hover:bg-[#282828] p-4 rounded-xl transition-all duration-300 cursor-pointer w-[160px] md:w-[190px] shrink-0 border border-transparent hover:border-white/5"
    >
      <div className={`relative w-full aspect-square mb-4 shadow-xl ${round ? 'rounded-full' : 'rounded-lg'} overflow-hidden`}>
        <img 
          src={imageUrl} 
          alt={displayTitle} 
          className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500 ease-out"
          loading="lazy"
        />
        {/* Play Button Overlay */}
        {!round && item.type !== 'artist' && (
          <div className="absolute bottom-2 right-2 translate-y-3 opacity-0 group-hover:translate-y-0 group-hover:opacity-100 transition-all duration-300 z-20">
             <button 
                onClick={handlePlayClick}
                className="bg-[#1DB954] text-black rounded-full p-3.5 shadow-xl flex items-center justify-center hover:scale-105 hover:bg-[#1ed760] active:scale-95 transition-all"
              >
                <Play size={22} fill="black" className="ml-1" />
              </button>
          </div>
        )}
      </div>
      <div className="flex flex-col gap-1 min-h-[52px]">
        <h3 className="text-white font-bold truncate text-[16px] leading-tight">
          {displayTitle}
        </h3>
        <p className="text-[#B3B3B3] text-[13px] truncate font-medium line-clamp-2">
          {safeSubtitle}
        </p>
      </div>
    </div>
  );
};

import React, { useRef, useEffect, useState } from 'react';
import { Play, Pause, SkipBack, SkipForward, ChevronDown, MoreHorizontal, Share2, ListMusic, Heart, Loader2, Shuffle, Repeat, Mic2, PlusCircle, CheckCircle2 } from 'lucide-react';
import { usePlayerStore } from '../store/playerStore';
import { getImageUrl, getAudioUrl, api } from '../services/api';
import { AnimatePresence, motion } from 'framer-motion';

export const Player: React.FC = () => {
  const { 
    currentSong, 
    isPlaying, 
    isBuffering,
    isFullScreen,
    setFullScreen,
    togglePlay, 
    setIsPlaying, 
    setIsBuffering,
    nextSong, 
    prevSong,
    queue,
    setQueue,
    likedSongs,
    toggleLike,
    isShuffling
  } = usePlayerStore();

  const audioRef = useRef<HTMLAudioElement>(null);
  const [progress, setProgress] = useState(0);
  const [duration, setDuration] = useState(0);
  const [dominantColor, setDominantColor] = useState<string>('#121212');
  const [isDragging, setIsDragging] = useState(false);
  const [touchStart, setTouchStart] = useState<{x: number, y: number} | null>(null);

  const isLiked = currentSong ? likedSongs.some(s => s.id === currentSong.id) : false;

  useEffect(() => {
    if (!currentSong) return;
    const imgUrl = getImageUrl(currentSong.image);
    const img = new Image();
    img.crossOrigin = "Anonymous";
    img.src = imgUrl;
    img.onload = () => {
      try {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        if (!ctx) return;
        canvas.width = 1; 
        canvas.height = 1;
        ctx.drawImage(img, 0, 0, 1, 1);
        const [r, g, b] = ctx.getImageData(0, 0, 1, 1).data;
        setDominantColor(`rgb(${r},${g},${b})`);
      } catch (e) { setDominantColor('#2a2a2a'); }
    };
  }, [currentSong]);

  useEffect(() => {
    if (!currentSong || !audioRef.current) return;
    const url = getAudioUrl(currentSong.downloadUrl);
    if (audioRef.current.src !== url) {
        audioRef.current.src = url;
        audioRef.current.load();
        if (isPlaying) {
             const playPromise = audioRef.current.play();
             if (playPromise !== undefined) playPromise.catch(() => setIsPlaying(false));
        }
    }
  }, [currentSong?.id]); 

  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;
    if (isPlaying && audio.paused) audio.play().catch(() => {});
    else if (!isPlaying && !audio.paused) audio.pause();
  }, [isPlaying]);

  const handleTimeUpdate = () => {
    if (audioRef.current && !isDragging) {
      setProgress(audioRef.current.currentTime);
      setDuration(audioRef.current.duration || 0);
    }
  };

  const handleEnded = async () => {
    if (currentSong && queue.findIndex(s => s.id === currentSong.id) === queue.length - 1) {
       try {
         const artist = currentSong.artists?.primary?.[0]?.name || "";
         const newSongs = (await api.searchSongs(`${artist} ${currentSong.language} songs`))
                          .filter(s => !queue.some(q => q.id === s.id)).slice(0, 5);
         if (newSongs.length > 0) setQueue([...queue, ...newSongs]);
       } catch (e) {}
    }
    nextSong();
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const time = parseFloat(e.target.value);
    setProgress(time);
    if (audioRef.current) audioRef.current.currentTime = time;
  };

  if (!currentSong) return null;

  const imageUrl = getImageUrl(currentSong.image);
  const primaryArtistName = currentSong.artists?.primary?.[0]?.name || "Unknown";

  return (
    <>
        <audio 
            ref={audioRef}
            preload="auto"
            onTimeUpdate={handleTimeUpdate}
            onEnded={handleEnded}
            onWaiting={() => setIsBuffering(true)}
            onPlaying={() => setIsBuffering(false)}
            onCanPlay={() => setIsBuffering(false)}
            onPause={() => { if (isPlaying && !isBuffering && audioRef.current?.paused) setIsPlaying(false); }}
            onPlay={() => !isPlaying && setIsPlaying(true)}
            onError={() => { setIsBuffering(false); setIsPlaying(false); }}
        />

        {/* FULL SCREEN PLAYER */}
        <AnimatePresence>
        {isFullScreen && (
        <motion.div 
            initial={{ y: "100%" }}
            animate={{ y: 0 }}
            exit={{ y: "100%" }}
            transition={{ type: "spring", damping: 30, stiffness: 300, mass: 0.8 }}
            className="fixed inset-0 z-[200] flex flex-col bg-[#000000] overflow-hidden"
            onTouchStart={(e) => setTouchStart({ x: e.targetTouches[0].clientX, y: e.targetTouches[0].clientY })}
            onTouchEnd={(e) => {
                if (!touchStart) return;
                const diffY = touchStart.y - e.changedTouches[0].clientY;
                if (diffY < -100) setFullScreen(false);
                setTouchStart(null);
            }}
        >
            {/* Dynamic Background */}
            <div className="absolute inset-0 z-0">
                <div className="absolute inset-0 bg-gradient-to-b from-black via-[#121212] to-black opacity-90 z-10"></div>
                <div 
                    className="absolute inset-0 transition-colors duration-1000 ease-in-out opacity-60 blur-3xl scale-110"
                    style={{ background: `linear-gradient(to bottom, ${dominantColor}, #000000)` }}
                />
            </div>

            <div className="relative z-20 flex flex-col h-full text-white px-6 pb-12 pt-6 md:px-12 md:pb-16 max-w-2xl mx-auto w-full">

                {/* Header */}
                <div className="flex items-center justify-between shrink-0 h-16">
                    <button onClick={() => setFullScreen(false)} className="p-2 -ml-2 text-white hover:bg-white/10 rounded-full transition-colors">
                        <ChevronDown size={32} />
                    </button>
                    <div className="flex flex-col items-center">
                        <span className="text-[10px] font-bold tracking-[0.2em] uppercase text-white/70">Playing From Playlist</span>
                        <span className="text-xs font-bold text-white mt-1">Discover Weekly</span>
                    </div>
                    <button className="p-2 -mr-2 text-white hover:bg-white/10 rounded-full transition-colors">
                        <MoreHorizontal size={24} />
                    </button>
                </div>

                {/* Artwork */}
                <div className="flex-1 flex items-center justify-center py-8 min-h-0">
                     <div className="relative w-full aspect-square max-h-[400px] shadow-[0_20px_50px_rgba(0,0,0,0.5)] rounded-xl overflow-hidden">
                        <img src={imageUrl} alt={currentSong.name} className="w-full h-full object-cover" />
                     </div>
                </div>

                {/* Track Info */}
                <div className="flex flex-col gap-6 shrink-0 w-full mb-4">
                    <div className="flex items-center justify-between">
                        <div className="flex flex-col overflow-hidden mr-6 flex-1">
                            <h1 className="text-2xl md:text-3xl font-bold text-white truncate leading-tight">{currentSong.name}</h1>
                            <p className="text-white/60 text-lg font-medium truncate mt-1">{primaryArtistName}</p>
                        </div>
                        <button onClick={() => toggleLike(currentSong)} className="transition-transform active:scale-75 hover:scale-110">
                            {isLiked ? <CheckCircle2 size={32} className="text-[#1DB954]" /> : <PlusCircle size={32} className="text-white/60 hover:text-white" />}
                        </button>
                    </div>

                    {/* Progress */}
                    <div className="group flex flex-col gap-2">
                        <div className="relative h-1.5 w-full bg-white/10 rounded-full touch-none group-hover:h-2 transition-all cursor-pointer">
                             <div 
                                className="absolute left-0 top-0 bottom-0 bg-white rounded-full transition-all duration-100"
                                style={{ width: `${(progress / (duration || 1)) * 100}%` }}
                             >
                                <div className="absolute right-0 top-1/2 -translate-y-1/2 w-3 h-3 bg-white rounded-full shadow-lg opacity-0 group-hover:opacity-100 transition-opacity"></div>
                             </div>
                             <input 
                                type="range" min="0" max={duration || 100} value={progress}
                                onChange={handleSeek}
                                onMouseDown={() => setIsDragging(true)} onMouseUp={() => setIsDragging(false)}
                                onTouchStart={() => setIsDragging(true)} onTouchEnd={() => setIsDragging(false)}
                                className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-30"
                            />
                        </div>
                        <div className="flex justify-between text-xs text-white/50 font-medium font-mono">
                            <span>{Math.floor(progress / 60)}:{(Math.floor(progress) % 60).toString().padStart(2, '0')}</span>
                            <span>{Math.floor(duration / 60)}:{(Math.floor(duration) % 60).toString().padStart(2, '0')}</span>
                        </div>
                    </div>

                    {/* Controls */}
                    <div className="flex items-center justify-between px-2">
                        <button className={`p-2 hover:text-white transition-colors ${isShuffling ? 'text-[#1DB954]' : 'text-white/40'}`}>
                            <Shuffle size={24} />
                        </button>
                        <div className="flex items-center gap-8">
                            <button onClick={prevSong} className="text-white hover:text-white/70 active:scale-90 transition-transform"><SkipBack size={36} fill="white" /></button>
                            <button 
                                onClick={togglePlay}
                                className="bg-white text-black rounded-full w-20 h-20 flex items-center justify-center hover:scale-105 active:scale-95 transition-all shadow-xl"
                            >
                                {isBuffering ? <Loader2 size={32} className="animate-spin" /> : isPlaying ? <Pause size={32} fill="black" /> : <Play size={32} fill="black" className="ml-1" />}
                            </button>
                            <button onClick={nextSong} className="text-white hover:text-white/70 active:scale-90 transition-transform"><SkipForward size={36} fill="white" /></button>
                        </div>
                        <button className="p-2 text-white/40 hover:text-white transition-colors"><Repeat size={24} /></button>
                    </div>
                </div>

                {/* Bottom Actions */}
                <div className="flex items-center justify-between px-4 mt-2">
                    <button className="text-white/50 hover:text-white"><Share2 size={22} /></button>
                    <button className="text-white/50 hover:text-white"><ListMusic size={24} /></button>
                </div>
            </div>
        </motion.div>
        )}
        </AnimatePresence>

        {/* MINI PLAYER - FLOATING ISLAND */}
        <AnimatePresence>
        {!isFullScreen && (
            <motion.div 
                initial={{ y: 100, opacity: 0 }}
                animate={{ y: 0, opacity: 1 }}
                exit={{ y: 100, opacity: 0 }}
                onClick={() => setFullScreen(true)}
                className="fixed bottom-[70px] md:bottom-6 left-4 right-4 md:left-[50%] md:translate-x-[-50%] md:w-[600px] h-[64px] bg-[#181818]/90 backdrop-blur-xl border border-white/10 rounded-2xl flex items-center pr-4 pl-2 shadow-2xl z-[150] cursor-pointer group hover:scale-[1.01] transition-all"
            >
                <div className="relative h-12 w-12 rounded-xl overflow-hidden ml-1 mr-3 shadow-md shrink-0">
                   <img src={imageUrl} alt="cover" className="h-full w-full object-cover" />
                </div>

                <div className="flex-1 min-w-0 flex flex-col justify-center mr-4">
                    <span className={`text-white font-bold text-sm truncate ${isPlaying ? 'text-[#1DB954]' : ''}`}>{currentSong.name}</span>
                    <span className="text-[#B3B3B3] text-xs truncate font-medium">{primaryArtistName}</span>
                </div>

                <div className="flex items-center gap-4">
                     <button onClick={(e) => { e.stopPropagation(); toggleLike(currentSong); }} className="text-white/40 hover:text-[#1DB954] transition-colors active:scale-90 hidden sm:block">
                        <Heart size={22} fill={isLiked ? "#1DB954" : "transparent"} className={isLiked ? "text-[#1DB954]" : ""} />
                     </button>
                     <button 
                        onClick={(e) => { e.stopPropagation(); togglePlay(); }} 
                        className="text-white w-10 h-10 flex items-center justify-center hover:scale-110 active:scale-90 transition-all rounded-full bg-white text-black"
                    >
                        {isBuffering ? <Loader2 size={20} className="animate-spin" /> : isPlaying ? <Pause size={20} fill="black" /> : <Play size={20} fill="black" className="ml-1" />}
                     </button>
                </div>

                {/* Subtle Bottom Progress */}
                <div className="absolute bottom-0 left-3 right-3 h-[2px] bg-white/5 rounded-full overflow-hidden mb-1">
                     <div className="h-full bg-white/80 rounded-full transition-all duration-200" style={{ width: `${(progress / (duration || 1)) * 100}%` }}></div>
                </div>
            </motion.div>
        )}
        </AnimatePresence>
    </>
  );
};

import React, { useEffect, useState } from 'react';
