export const Home: React.FC = () => {
  const [daylist, setDaylist] = useState<Song[]>([]);
  const [recent, setRecent] = useState<(Song | Album)[]>([]); 
  const { history, playSong, currentUser } = usePlayerStore();
  const navigate = useNavigate();
  const [isLoading, setIsLoading] = useState(true);
  const [greeting, setGreeting] = useState('Good Morning');

  useEffect(() => {
    const fetchData = async () => {
      setIsLoading(true);
      const hour = new Date().getHours();

      if (hour < 12) setGreeting('Good morning');
      else if (hour < 18) setGreeting('Good afternoon');
      else setGreeting('Good evening');

      let query = hour < 12 ? 'Morning Acoustic' : hour < 18 ? 'Upbeat Pop' : 'Late Night Vibes';

      try {
        const songs = await api.searchSongs(query);
        await new Promise(r => setTimeout(r, 400));
        setDaylist(songs);
      } catch (e) { console.error(e); } 
      finally { setIsLoading(false); }
    };
    fetchData();
  }, []);

  useEffect(() => {
    if (history.length > 0) {
      setRecent(history.slice(0, 6));
    } else {
       Promise.all([
         api.searchSongs("The Weeknd"),
         api.searchAlbums("Starboy"),
         api.searchSongs("Taylor Swift"),
         api.searchAlbums("1989"),
       ]).then(([s1, a1, s2, a2]) => setRecent([...s1.slice(0,1), ...a1.slice(0,1), ...s2.slice(0,1), ...a2.slice(0,1)]));
    }
  }, [history]);

  const ShortcutCard: React.FC<{ title: string, image?: string, isLikedSongs?: boolean, onClick?: () => void }> = ({ title, image, isLikedSongs = false, onClick }) => (
    <div 
        onClick={onClick}
        className="group relative h-[56px] md:h-[64px] flex items-center bg-[#181818]/60 hover:bg-[#2A2A2A] rounded-md overflow-hidden cursor-pointer transition-colors shadow-sm border border-transparent hover:border-white/5"
    >
        {isLikedSongs ? (
            <div className="h-full w-[56px] md:w-[64px] bg-gradient-to-br from-[#450af5] to-[#c4efd9] flex items-center justify-center shrink-0">
                <svg role="img" height="24" width="24" aria-hidden="true" viewBox="0 0 24 24" fill="white"><path d="M15.724 4.22A4.313 4.313 0 0 0 12.192.814a4.269 4.269 0 0 0-3.622 1.13.837.837 0 0 1-1.14 0 4.272 4.272 0 0 0-6.21 5.855l5.916 7.05a1.128 1.128 0 0 0 1.727 0l5.916-7.05a4.228 4.228 0 0 0 .945-3.577z"></path></svg>
            </div>
        ) : (
            <img src={image} className="h-full w-[56px] md:w-[64px] object-cover shrink-0" alt=""/>
        )}
        <span className="font-bold text-[13px] md:text-[14px] px-3 text-white truncate flex-1">{title}</span>

        {/* Play Button (Hidden until hover) */}
        {!isLikedSongs && (
          <div className="absolute right-3 opacity-0 group-hover:opacity-100 transition-opacity bg-[#1DB954] rounded-full p-2 shadow-lg">
             <svg role="img" height="16" width="16" aria-hidden="true" viewBox="0 0 24 24" fill="black"><path d="m7.05 3.606 13.49 7.788a.7.7 0 0 1 0 1.212L7.05 20.394A.7.7 0 0 1 6 19.788V4.212a.7.7 0 0 1 1.05-.606z"></path></svg>
          </div>
        )}
    </div>
  );

  return (
    <div className="flex flex-col min-h-full pb-36 relative bg-black">

      {/* Subtle Dynamic Gradient Background */}
      <div className="absolute top-0 left-0 right-0 h-[400px] bg-gradient-to-b from-[#202020] via-[#101010] to-black opacity-100 pointer-events-none z-0" />

      <div className="relative z-10 p-4 md:p-6 flex flex-col gap-8">

          {/* Header */}
          <div className="flex items-center justify-between">
              <div className="flex items-center gap-3">
                 <div onClick={() => navigate(currentUser ? '/profile' : '/login')} className="w-9 h-9 rounded-full bg-[#1DB954] flex items-center justify-center font-bold text-black text-sm cursor-pointer hover:scale-105 transition-transform border border-black/20">
                     {currentUser?.image ? <img src={currentUser.image} className="w-full h-full rounded-full object-cover" /> : currentUser ? currentUser.name[0] : <UserCircle size={24} />}
                 </div>
                 <div className="flex gap-2">
                    <button className="px-3 py-1 bg-white/10 text-white rounded-full text-xs font-bold hover:bg-white/20 transition-colors backdrop-blur-sm">All</button>
                    <button className="px-3 py-1 bg-transparent text-white rounded-full text-xs font-bold hover:bg-white/10 transition-colors">Music</button>
                 </div>
              </div>
          </div>

          {/* Welcome & Shortcuts */}
          <div>
              <h1 className="text-3xl font-bold text-white mb-4 tracking-tight">{greeting}</h1>
              <div className="grid grid-cols-2 md:grid-cols-2 lg:grid-cols-3 gap-3">
                <ShortcutCard title="Liked Songs" isLikedSongs onClick={() => navigate('/library')} />
                {isLoading || recent.length === 0 ? (
                    Array(5).fill(0).map((_, i) => <SkeletonShortcut key={i} />)
                ) : (
                    recent.slice(0, 5).map((item, idx) => (
                        <ShortcutCard 
                            key={item.id + idx} 
                            title={item.name} 
                            image={getImageUrl(item.image)}
                            onClick={() => item.type === 'song' ? playSong(item as Song, [item as Song]) : navigate(`/album/${item.id}`)}
                        />
                    ))
                )}
              </div>
          </div>

          {/* Made For You */}
          <section>
            <h2 className="text-2xl font-bold text-white mb-4 hover:underline cursor-pointer">Made For You</h2>
            <div className="flex overflow-x-auto gap-5 pb-4 no-scrollbar -mx-4 px-4">
                {isLoading ? Array(5).fill(0).map((_, i) => <SkeletonCard key={i} />) : daylist.map((item, i) => <SongCard key={i} item={item} onPlay={() => playSong(item, daylist)} />)}
            </div>
          </section>

          {/* Artists */}
           <section>
            <h2 className="text-2xl font-bold text-white mb-4 hover:underline cursor-pointer">Your favorite artists</h2>
            <div className="flex overflow-x-auto gap-5 pb-4 no-scrollbar -mx-4 px-4">
                {isLoading ? Array(5).fill(0).map((_, i) => <SkeletonCard key={i} round />) : daylist.slice(0,6).map((item, i) => <SongCard key={i} item={item} round />)}
            </div>
          </section>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Search as SearchIcon, ArrowLeft, X, TrendingUp, MoreVertical, PlusCircle, CheckCircle2, Music } from 'lucide-react';
import { api, getImageUrl } from '../services/api';
import { Song, Album, Artist } from '../types';
import { usePlayerStore } from '../store/playerStore';
import { useNavigate } from 'react-router-dom';

export const Search: React.FC = () => {
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [results, setResults] = useState<{ songs: Song[], albums: Album[], artists: Artist[] }>({ songs: [], albums: [], artists: [] });
  const { playSong, likedSongs, toggleLike } = usePlayerStore();
  const navigate = useNavigate();

  useEffect(() => {
    const timer = setTimeout(async () => {
      if (query.trim()) {
        try {
           const [songs, albums, artists] = await Promise.all([
              api.searchSongs(query),
              api.searchAlbums(query),
              api.searchArtists(query)
           ]);
           setResults({ songs, albums, artists });

           const newSuggestions = new Set<string>();
           songs.slice(0, 2).forEach(s => newSuggestions.add(s.name));
           artists.slice(0, 2).forEach(a => newSuggestions.add(a.name));
           setSuggestions(Array.from(newSuggestions).slice(0, 5));
        } catch (e) { console.error(e); }
      } else {
          setResults({ songs: [], albums: [], artists: [] });
          setSuggestions([]);
      }
    }, 300); 
    return () => clearTimeout(timer);
  }, [query]);

  const BrowseCard = ({ title, color, image }: { title: string, color: string, image?: string }) => (
    <div className={`aspect-[1.5/1] ${color} rounded-xl p-4 relative overflow-hidden cursor-pointer hover:scale-[1.02] transition-all duration-300 shadow-md group`}>
        <h3 className="text-white font-bold text-xl relative z-10 break-words max-w-[80%]">{title}</h3>
        <div className="absolute -bottom-4 -right-4 w-24 h-24 bg-black/20 rounded-md shadow-2xl rotate-[25deg] group-hover:rotate-[30deg] group-hover:scale-110 transition-transform duration-500">
             {image ? <img src={image} className="w-full h-full object-cover" alt="" /> : <div className="w-full h-full bg-white/10" />}
        </div>
    </div>
  );

  return (
    <div className="flex flex-col min-h-full pb-32 pt-20 px-4 md:px-8 relative bg-black">

      {/* Fixed Search Header */}
      <div className="absolute top-0 left-0 right-0 z-40 px-4 py-4 bg-black/80 backdrop-blur-xl border-b border-white/5">
          <div className="relative max-w-[400px] flex items-center gap-3">
             <button onClick={() => navigate(-1)} className="md:hidden p-2 rounded-full hover:bg-white/10 text-white"><ArrowLeft size={24} /></button>
             <div className="relative flex-1 group">
                <div className="absolute inset-y-0 left-3.5 flex items-center pointer-events-none">
                    <SearchIcon size={20} className="text-[#B3B3B3] group-focus-within:text-white transition-colors" />
                </div>
                <input 
                  type="text"
                  className="w-full bg-[#242424] hover:bg-[#2A2A2A] focus:bg-[#2A2A2A] text-white rounded-full py-3.5 pl-11 pr-10 focus:outline-none focus:ring-2 focus:ring-white/20 font-medium text-[15px] transition-all placeholder-[#777]"
                  placeholder="What do you want to listen to?"
                  value={query}
                  onChange={(e) => setQuery(e.target.value)}
                  autoFocus
                />
                {query && (
                    <button onClick={() => setQuery('')} className="absolute right-3 top-1/2 -translate-y-1/2 text-white/50 hover:text-white p-1">
                        <X size={18} />
                    </button>
                )}
             </div>
          </div>
      </div>

      {/* Default Browse View */}
      {!query && (
         <div className="flex flex-col gap-8 pt-4">
            <section>
                <h2 className="text-white font-bold text-xl mb-4">Browse all</h2>
                <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
                    <BrowseCard title="Podcasts" color="bg-[#27856A]" />
                    <BrowseCard title="Live Events" color="bg-[#8D67AB]" />
                    <BrowseCard title="Made For You" color="bg-[#1E3264]" />
                    <BrowseCard title="New Releases" color="bg-[#E8115B]" />
                    <BrowseCard title="Hindi" color="bg-[#E91429]" />
                    <BrowseCard title="Punjabi" color="bg-[#B02897]" />
                    <BrowseCard title="Tamil" color="bg-[#A56752]" />
                    <BrowseCard title="Ghazals" color="bg-[#D84000]" />
                    <BrowseCard title="Pop" color="bg-[#148A08]" />
                    <BrowseCard title="Hip-Hop" color="bg-[#BC5900]" />
                </div>
            </section>
         </div>
      )}

      {/* Search Results */}
      {query && (
        <div className="flex flex-col w-full pb-8">
            {/* Top Match could go here */}

            {/* Song Results */}
            {results.songs.length > 0 && (
                <div className="mt-4">
                     <h2 className="text-white font-bold mb-4 text-2xl">Songs</h2>
                     {results.songs.map(song => {
                         const isLiked = likedSongs.some(s => s.id === song.id);
                         const artistName = song.artists?.primary?.[0]?.name || "Unknown Artist";

                         return (
                             <div key={song.id} className="flex items-center gap-4 px-3 py-2 hover:bg-white/10 cursor-pointer rounded-md group transition-colors" onClick={() => playSong(song, results.songs)}>
                                 <div className="relative w-12 h-12 shrink-0">
                                    <img src={getImageUrl(song.image)} className="w-full h-full rounded object-cover" alt="" />
                                    <div className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity rounded">
                                        <Music size={16} className="text-white"/>
                                    </div>
                                 </div>
                                 <div className="flex-1 min-w-0">
                                     <div className={`font-medium truncate text-[16px] text-white`}>{song.name}</div>
                                     <div className="text-[#B3B3B3] text-sm truncate">{artistName}</div>
                                 </div>

                                 <button 
                                    className="text-[#B3B3B3] hover:text-white transition-transform active:scale-90 opacity-0 group-hover:opacity-100" 
                                    onClick={(e) => { e.stopPropagation(); toggleLike(song); }}
                                 >
                                    {isLiked ? <CheckCircle2 size={20} className="text-[#1DB954]" /> : <PlusCircle size={20} />}
                                 </button>
                                 <div className="text-sm text-[#B3B3B3] font-mono">
                                     {(parseInt(song.duration) / 60).toFixed(0)}:{(parseInt(song.duration) % 60).toString().padStart(2, '0')}
                                 </div>
                             </div>
                         );
                     })}
                </div>
            )}
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { authService } from '../services/auth';
import { usePlayerStore } from '../store/playerStore';
import { Music, ArrowLeft, Loader2 } from 'lucide-react';

export const Login: React.FC = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const navigate = useNavigate();
