      <div className="absolute -top-[20%] -left-[20%] w-[60%] h-[60%] bg-[#1DB954]/10 rounded-full blur-[120px]"></div>
      <div className="absolute top-[40%] right-[10%] w-[40%] h-[40%] bg-blue-900/10 rounded-full blur-[100px]"></div>

      <div className="w-full max-w-[400px] z-10 bg-black/40 backdrop-blur-2xl p-8 rounded-2xl border border-white/5 shadow-2xl">

        <div className="flex flex-col items-center gap-4 mb-8">
           <div className="w-14 h-14 bg-white rounded-full flex items-center justify-center shadow-lg hover:scale-105 transition-transform">
               <Music size={28} className="text-black" />
           </div>
           <h1 className="text-3xl font-black tracking-tight">Log in to VibeStream</h1>
        </div>

        <form onSubmit={handleLogin} className="flex flex-col gap-4">
           {error && (
             <div className="bg-red-500/10 border border-red-500/20 text-red-500 p-3 rounded-lg text-sm text-center font-medium">
               {error}
             </div>
           )}

           <div className="flex flex-col gap-2">
              <label className="text-xs font-bold uppercase tracking-wider text-[#B3B3B3] pl-1">Email</label>
              <input 
                type="email" 
                required
                className="bg-[#121212] border border-[#333] rounded-lg p-3.5 focus:outline-none focus:border-white/50 focus:bg-[#1A1A1A] transition-all text-sm font-medium"
                placeholder="name@domain.com"
                value={email}
                onChange={e => setEmail(e.target.value)}
              />
           </div>

           <div className="flex flex-col gap-2">
              <label className="text-xs font-bold uppercase tracking-wider text-[#B3B3B3] pl-1">Password</label>
              <input 
                type="password" 
                required
                className="bg-[#121212] border border-[#333] rounded-lg p-3.5 focus:outline-none focus:border-white/50 focus:bg-[#1A1A1A] transition-all text-sm font-medium"
                placeholder="Password"
                value={password}
                onChange={e => setPassword(e.target.value)}
              />
           </div>

           <button 
              type="submit" 
              disabled={loading}
              className="bg-[#1DB954] text-black font-bold py-3.5 rounded-full hover:scale-[1.02] hover:bg-[#1ed760] active:scale-[0.98] transition-all mt-6 flex items-center justify-center shadow-lg"
           >
              {loading ? <Loader2 size={20} className="animate-spin" /> : 'Log In'}
           </button>
        </form>

        <div className="my-8 h-[1px] bg-gradient-to-r from-transparent via-[#333] to-transparent w-full"></div>

        <div className="text-center text-[#B3B3B3] text-sm">
           Don't have an account? <Link to="/signup" className="text-white hover:underline font-bold ml-1">Sign up</Link>
        </div>
      </div>
    </div>
  );
};

