import { User, ChatMessage, UserPlaylist } from '../types';
import { auth, db } from './firebase';
import { 
  createUserWithEmailAndPassword, 
  signInWithEmailAndPassword, 
  signOut 
} from 'firebase/auth';
import { 
  doc, 
  setDoc, 
  getDoc, 
  updateDoc, 
  collection, 
  query, 
  where, 
  getDocs,
  onSnapshot
} from 'firebase/firestore';

// Helper to remove undefined values which Firestore hates
const cleanData = (obj: any) => {
  return JSON.parse(JSON.stringify(obj));
};

export const authService = {

  // 1. SIGN UP
  signup: async (name: string, email: string, password: string): Promise<User> => {
    try {
      const userCredential = await createUserWithEmailAndPassword(auth, email, password);
      const uid = userCredential.user.uid;

      const newUser: User = {
        name,
        email,
        image: '',
        friends: [],
        playlists: [],
      };

      await setDoc(doc(db, "users", uid), cleanData({
        ...newUser,
        likedSongs: [],
        history: [],
        chats: {},
        settings: { volume: 1 },
        currentActivity: { status: 'online', timestamp: Date.now() }
      }));

      return {
        ...newUser,
        // @ts-ignore 
        likedSongs: [],
        history: [],
        chats: {}
      };

    } catch (error: any) {
      if (error.code === 'auth/email-already-in-use') {
        throw new Error('User already exists.');
      }
      throw new Error(error.message || 'Signup failed');
    }
  },

  // 2. LOGIN
  login: async (email: string, password: string): Promise<User & { chats?: any, likedSongs?: any[], history?: any[] }> => {
    try {
      const userCredential = await signInWithEmailAndPassword(auth, email, password);
      const uid = userCredential.user.uid;

      // Set status to online immediately
      await updateDoc(doc(db, "users", uid), {
        "currentActivity.status": "online",
        "currentActivity.timestamp": Date.now()
      });

      const userDocRef = doc(db, "users", uid);
      const userDoc = await getDoc(userDocRef);

      if (!userDoc.exists()) {
        throw new Error("User data not found");
      }

      const userData = userDoc.data();

      return {
        email: userData.email,
        name: userData.name,
        image: userData.image,
        friends: userData.friends || [],
        playlists: userData.playlists || [],
        likedSongs: userData.likedSongs || [],
        history: userData.history || [],
        chats: userData.chats || {},
        currentActivity: userData.currentActivity
      };

    } catch (error: any) {
      if (
        error.code === 'auth/invalid-credential' || 
        error.code === 'auth/user-not-found' || 
        error.code === 'auth/wrong-password' ||
        error.code === 'auth/invalid-email'
      ) {
        throw new Error("Password or Email Incorrect");
      }
      throw error;
    }
  },

  // --- PLAYLIST SHARING ---

  savePublicPlaylist: async (playlist: UserPlaylist) => {
    try {
      // Save to a global 'playlists' collection so it can be fetched by ID by anyone
      // Use cleanData to avoid undefined errors
      await setDoc(doc(db, "global_playlists", playlist.id), cleanData(playlist));
    } catch (e) {
      console.error("Failed to save public playlist", e);
    }
  },

  getPublicPlaylist: async (playlistId: string): Promise<UserPlaylist | null> => {
    try {
      const docRef = doc(db, "global_playlists", playlistId);
      const docSnap = await getDoc(docRef);
      if (docSnap.exists()) {
        return docSnap.data() as UserPlaylist;
      }
      return null;
    } catch (e) {
      console.error("Failed to fetch public playlist", e);
      return null;
    }
  },

  // --- REALTIME LISTENERS ---

  // Listen to MY user document
  subscribeToUserData: (callback: (data: any) => void) => {
    if (!auth.currentUser) return () => {};

    const userRef = doc(db, "users", auth.currentUser.uid);
    return onSnapshot(userRef, (doc) => {
      if (doc.exists()) {
        callback(doc.data());
      }
    });
  },

  // Listen to CONTACTS (Online Status, Song)
  subscribeToFriendsActivity: (friendEmails: string[], callback: (friendsData: any[]) => void) => {
    if (!friendEmails || friendEmails.length === 0) {
      callback([]);
      return () => {};
    }

    // Firestore 'in' query supports max 10. 
    // We slice to 10 for safety in this demo.
    const usersRef = collection(db, "users");
    const safeEmails = friendEmails.slice(0, 10); 

    const q = query(usersRef, where("email", "in", safeEmails));

    return onSnapshot(q, (snapshot) => {
      const friendsData = snapshot.docs.map(d => d.data());
      callback(friendsData);
    });
  },

  // --- ACTIONS ---

  // Add Contact (Directly adds to friend list)
  addContact: async (contactEmail: string) => {
    if (!auth.currentUser) throw new Error("Not authenticated");
    const myRef = doc(db, "users", auth.currentUser.uid);
    const myDoc = await getDoc(myRef);

    if (myDoc.exists()) {
      const data = myDoc.data();
      const currentFriends = data.friends || [];
      if (!currentFriends.includes(contactEmail)) {
        await updateDoc(myRef, {
          friends: [...currentFriends, contactEmail]
        });
      }
    }
  },

  sendChatMessage: async (senderEmail: string, receiverEmail: string, message: ChatMessage) => {
    if (!auth.currentUser) return;

    // 1. Update Me
    const myRef = doc(db, "users", auth.currentUser.uid);
    const safeMessage = cleanData(message);

    try {
        const myDoc = await getDoc(myRef);
        if (myDoc.exists()) {
            const myData = myDoc.data();
            const myChats = myData.chats || {};
            const chatWithReceiver = myChats[receiverEmail] || [];
            const myFriends = myData.friends || [];

            // Add receiver to my friends list if not there (Automatic contact addition)
            const updates: any = {
                 [`chats.${receiverEmail.replace(/\./g, '_dot_')}`]: [...chatWithReceiver, safeMessage]
            };

            if (!myFriends.includes(receiverEmail)) {
                updates.friends = [...myFriends, receiverEmail];
            }

            await updateDoc(myRef, updates).catch(async () => {
                 // Fallback for dot notation
                 myChats[receiverEmail] = [...chatWithReceiver, safeMessage];
                 const fallbackUpdates: any = { chats: myChats };
                 if (!myFriends.includes(receiverEmail)) {
                     fallbackUpdates.friends = [...myFriends, receiverEmail];
                 }
                 await updateDoc(myRef, fallbackUpdates);
            });
        }

        // 2. Update Friend (Receiver)
        const usersRef = collection(db, "users");
        const q = query(usersRef, where("email", "==", receiverEmail));
        const querySnapshot = await getDocs(q);

        if (!querySnapshot.empty) {
            const friendDoc = querySnapshot.docs[0];
            const friendData = friendDoc.data();
            const friendChats = friendData.chats || {};
            const friendFriends = friendData.friends || [];
            const chatWithSender = friendChats[senderEmail] || [];

            const updatedFriendChats = {
                ...friendChats,
                [senderEmail]: [...chatWithSender, safeMessage]
            };

            const friendUpdates: any = {
                chats: updatedFriendChats
            };

            // Add sender to receiver's friends list if not there (Reciprocal contact addition)
            if (!friendFriends.includes(senderEmail)) {
                friendUpdates.friends = [...friendFriends, senderEmail];
            }

            await updateDoc(friendDoc.ref, friendUpdates);
        }
    } catch (e) {
        console.error("Failed to send message", e);
        throw e;
    }
  },

  updateUserStatus: async (status: 'online' | 'offline' | 'listening', song?: any) => {
     if (!auth.currentUser) return;
     const userRef = doc(db, "users", auth.currentUser.uid);

     const activity = cleanData({
         status,
         timestamp: Date.now(),
         song: song || null
     });

     await updateDoc(userRef, {
         currentActivity: activity
     });
  },

  syncPublicProfile: async (user: User, chats?: Record<string, ChatMessage[]>) => {
    if (!auth.currentUser) return;
    const userRef = doc(db, "users", auth.currentUser.uid);
    const updates: any = {
      name: user.name,
      image: user.image,
      friends: user.friends,
      playlists: user.playlists 
    };
    if (chats) updates.chats = chats;
    await updateDoc(userRef, cleanData(updates));
  },

  syncPrivateData: async (user: User, additionalData: any) => {
     if (!auth.currentUser) return;
     const userRef = doc(db, "users", auth.currentUser.uid);
     await updateDoc(userRef, cleanData({
         playlists: user.playlists, 
         likedSongs: additionalData.likedSongs,
         history: additionalData.history
     }));
  },

  searchUsers: async (queryText: string) => {
      const usersRef = collection(db, "users");
      const q = query(usersRef); 
      const querySnapshot = await getDocs(q);
      const results: any[] = [];
      const lowerQ = queryText.toLowerCase();

      querySnapshot.forEach((doc) => {
          const data = doc.data();
          if (
              (data.name && data.name.toLowerCase().includes(lowerQ)) || 
              (data.email && data.email.toLowerCase().includes(lowerQ))
          ) {
              results.push({
                  name: data.name,
                  email: data.email,
                  image: data.image
              });
          }
      });
      return results.slice(0, 10);
  },

  logout: async () => {
      if (auth.currentUser) {
           const userRef = doc(db, "users", auth.currentUser.uid);
           await updateDoc(userRef, { "currentActivity.status": "offline" }).catch(console.error);
      }
      await signOut(auth);
  }
};

import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import { Song, UserPlaylist, User, Friend, ChatMessage, PartySession } from '../types';
import { authService } from '../services/auth';

interface PlayerState {
  isPlaying: boolean;
  isBuffering: boolean;
  isFullScreen: boolean;
  currentSong: Song | null;
  queue: Song[];
  history: Song[];
  likedSongs: Song[];
  userPlaylists: UserPlaylist[];
  volume: number;
  isShuffling: boolean;

  // Auth
  currentUser: User | null;

  // Social
  friends: Friend[]; // Unified list
  searchResults: { name: string, email: string, image?: string }[];
  activeChatFriendId: string | null;
  partySession: PartySession | null;

  // Realtime Cleanup
  unsubscribers: Function[];

  // Actions
  playSong: (song: Song, newQueue?: Song[]) => void;
  togglePlay: () => void;
  setIsPlaying: (isPlaying: boolean) => void;
  setIsBuffering: (isBuffering: boolean) => void;
  setFullScreen: (isFull: boolean) => void;
  nextSong: () => void;
  prevSong: () => void;
  addToQueue: (song: Song) => void;
  setQueue: (songs: Song[]) => void;
  setVolume: (val: number) => void;
  addToHistory: (song: Song) => void;
  toggleLike: (song: Song) => void;
  createPlaylist: (playlist: UserPlaylist) => void;
  importPlaylist: (playlist: UserPlaylist) => void;
  addSongToPlaylist: (playlistId: string, song: Song) => void;
  removePlaylist: (id: string) => void;

  // Auth Actions
  loginUser: (user: User & { likedSongs?: Song[], history?: Song[], chats?: any }) => void;
  logoutUser: () => void;
  syncUserToCloud: (type?: 'public' | 'private' | 'both') => void;
  updateUserProfile: (name: string, image?: string) => void;
  initRealtimeListeners: () => void;

  // Social Actions
  searchUsers: (query: string) => Promise<void>;
  addContact: (email: string) => Promise<void>;
  refreshFriendsActivity: () => Promise<void>;
  openChat: (friendId: string | null) => void;
  sendMessage: (friendId: string, text: string) => void;
  startParty: () => void;
  stopParty: () => void;
}

export const usePlayerStore = create<PlayerState>()(
  persist(
    (set, get) => ({
      isPlaying: false,
      isBuffering: false,
      isFullScreen: false,
      currentSong: null,
      queue: [],
      history: [],
      likedSongs: [],
      userPlaylists: [],
      volume: 1,
      isShuffling: false,
      currentUser: null,

      // Social Initial State
      friends: [],
      searchResults: [],
      activeChatFriendId: null,
      partySession: null,
      unsubscribers: [],

      playSong: (song, newQueue) => {
        const { addToHistory, currentUser } = get();
        addToHistory(song);

        if (currentUser) {
            authService.updateUserStatus('listening', song);
        }

        set((state) => ({
          currentSong: song,
          isPlaying: true,
          isBuffering: true, 
          queue: newQueue ? newQueue : state.queue,
          isFullScreen: false, // Changed: Do not auto-open full player
        }));
      },

      togglePlay: () => set((state) => ({ isPlaying: !state.isPlaying })),

      setIsPlaying: (isPlaying) => {
          set({ isPlaying });
          const { currentUser, currentSong } = get();
          if (currentUser && !isPlaying) {
             authService.updateUserStatus('online', currentSong);
          }
      },

      setIsBuffering: (isBuffering) => set({ isBuffering }),
      setFullScreen: (isFullScreen) => set({ isFullScreen }),

      nextSong: () => {
        const { queue, currentSong, isShuffling } = get();
        if (!currentSong) return;
        const currentIndex = queue.findIndex(s => s.id === currentSong.id);
        let nextIndex = isShuffling ? Math.floor(Math.random() * queue.length) : currentIndex + 1;
        if (nextIndex < queue.length) get().playSong(queue[nextIndex]);
        else set({ isPlaying: false });
      },

      prevSong: () => {
        const { queue, currentSong } = get();
        if (!currentSong) return;
        const currentIndex = queue.findIndex(s => s.id === currentSong.id);
        if (currentIndex - 1 >= 0) get().playSong(queue[currentIndex - 1]);
      },

      addToQueue: (song) => set((state) => ({ queue: [...state.queue, song] })),
      setQueue: (songs) => set({ queue: songs }),
      setVolume: (volume) => set({ volume }),

      addToHistory: (song) => {
          set((state) => {
            const newHistory = [song, ...state.history.filter(s => s.id !== song.id)].slice(0, 20);
            setTimeout(() => get().syncUserToCloud('private'), 1000);
            return { history: newHistory };
          });
      },

      toggleLike: (song) => {
          set((state) => {
            const isLiked = state.likedSongs.some(s => s.id === song.id);
            const newLiked = isLiked ? state.likedSongs.filter(s => s.id !== song.id) : [song, ...state.likedSongs];
            setTimeout(() => get().syncUserToCloud('private'), 1000);
            return { likedSongs: newLiked };
          });
      },

      createPlaylist: (playlist) => {
        set((state) => {
           const newPlaylists = [playlist, ...state.userPlaylists];

           // Also save to global playlists for sharing
           authService.savePublicPlaylist(playlist);

           if (state.currentUser) {
             const updatedUser = { ...state.currentUser, playlists: newPlaylists };
             setTimeout(() => get().syncUserToCloud('private'), 1000);
             return { userPlaylists: newPlaylists, currentUser: updatedUser };
           }
           return { userPlaylists: newPlaylists };
        });
      },

      importPlaylist: (playlist) => {
        set((state) => {
           // Avoid duplicates
           if (state.userPlaylists.some(p => p.id === playlist.id)) return {};

           const newPlaylists = [playlist, ...state.userPlaylists];
           if (state.currentUser) {
             const updatedUser = { ...state.currentUser, playlists: newPlaylists };
             setTimeout(() => get().syncUserToCloud('private'), 1000);
             return { userPlaylists: newPlaylists, currentUser: updatedUser };
           }
           return { userPlaylists: newPlaylists };
        });
      },

      addSongToPlaylist: (playlistId, song) => {
        set((state) => {
          const newPlaylists = state.userPlaylists.map(p => {
            if (p.id === playlistId) {
               // Update global copy too if it exists there
               const updated = { ...p, songs: [...p.songs, song] };
               if (p.songs.some(s => s.id === song.id)) return p;

               authService.savePublicPlaylist(updated);
               return updated;
            }
            return p;
          });
          if (state.currentUser) {
             const updatedUser = { ...state.currentUser, playlists: newPlaylists };
             setTimeout(() => get().syncUserToCloud('private'), 1000);
             return { userPlaylists: newPlaylists, currentUser: updatedUser };
           }
           return { userPlaylists: newPlaylists };
        });
      },

      removePlaylist: (id) => {
        set((state) => {
           const newPlaylists = state.userPlaylists.filter(p => p.id !== id);
           if (state.currentUser) {
             const updatedUser = { ...state.currentUser, playlists: newPlaylists };
             setTimeout(() => get().syncUserToCloud('private'), 1000);
             return { userPlaylists: newPlaylists, currentUser: updatedUser };
           }
           return { userPlaylists: newPlaylists };
        });
      },

      loginUser: (user) => {
          set({ 
            currentUser: user, 
            userPlaylists: user.playlists || [],
            likedSongs: user.likedSongs || [],
            history: user.history || [],
          });
          get().initRealtimeListeners();
      },

      initRealtimeListeners: () => {
         const { unsubscribers, currentUser } = get();
         // Cleanup old listeners
         unsubscribers.forEach(unsub => unsub());

         if (!currentUser) {
             set({ unsubscribers: [] });
             return;
         }

         const newUnsubscribers: Function[] = [];

         // 1. Listen to MY DATA (Chats, Contact List changes)
         const unsubUser = authService.subscribeToUserData((data) => {
             set((state) => {
                 const updatedUser = { ...state.currentUser, ...data } as User;

                 const existingFriends = state.friends;
                 const serverContactEmails = data.friends || [];
                 const serverChats = data.chats || {};

                 // Reconstruct friends array based on server email list
                 const mergedFriends: Friend[] = serverContactEmails.map((email: string) => {
                     // Find existing state for this friend to keep status/song
                     const existing = existingFriends.find(f => f.id === email);

                     // Get chats from my doc
                     const chatHistory = serverChats[email] || serverChats[email.replace(/\./g, '_dot_')] || [];

                     return {
                         id: email,
                         name: existing?.name || email.split('@')[0], 
                         image: existing?.image || '',
                         status: existing?.status || 'offline', 
                         currentSong: existing?.currentSong || null, 
                         lastActive: existing?.lastActive || 0,
                         chatHistory: chatHistory
                     };
                 });

                 return {
                     currentUser: updatedUser,
                     friends: mergedFriends,
                     userPlaylists: data.playlists || state.userPlaylists
                 };
             });
         });
         newUnsubscribers.push(unsubUser);

         // 2. Listen to CONTACTS ACTIVITY (Status, Song)
         if (currentUser.friends && currentUser.friends.length > 0) {
             const unsubFriends = authService.subscribeToFriendsActivity(currentUser.friends, (friendsData) => {
                 set((state) => {
                     const updatedFriends = state.friends.map(f => {
                         const liveData = friendsData.find((d: any) => d.email === f.id);
                         if (liveData) {
                             return {
                                 ...f,
                                 name: liveData.name || f.name,
                                 image: liveData.image || f.image,
                                 status: liveData.currentActivity?.status || 'offline',
                                 currentSong: liveData.currentActivity?.song || null,
                                 lastActive: liveData.currentActivity?.timestamp || 0
                             };
                         }
                         return f;
                     });
                     return { friends: updatedFriends };
                 });
             });
             newUnsubscribers.push(unsubFriends);
         }

         set({ unsubscribers: newUnsubscribers });
      },

      logoutUser: async () => {
        get().unsubscribers.forEach(unsub => unsub());
        await authService.logout();
        set({ 
            currentUser: null, 
            userPlaylists: [],
            friends: [],
            partySession: null,
            likedSongs: [],
            history: [],
            unsubscribers: []
        });
      },

      syncUserToCloud: async (type = 'both') => {
         const { currentUser, userPlaylists, likedSongs, history } = get();
         if (!currentUser) return;
         const updatedUser = { ...currentUser, playlists: userPlaylists };
         try {
             if (type === 'public' || type === 'both') await authService.syncPublicProfile(updatedUser);
             if (type === 'private' || type === 'both') await authService.syncPrivateData(updatedUser, { likedSongs, history });
         } catch (e) {
             console.error("Sync failed", e);
         }
      },

      updateUserProfile: (name, image) => {
        set((state) => {
          if (!state.currentUser) return {};
          const updatedUser = { 
              ...state.currentUser, 
              name: name,
              image: image !== undefined ? image : state.currentUser.image 
          };
          setTimeout(() => get().syncUserToCloud('public'), 100);
          return { currentUser: updatedUser };
        });
      },

      searchUsers: async (query) => {
          try {
              const results = await authService.searchUsers(query);
              const { currentUser } = get();
              const filtered = results.filter(u => u.email !== currentUser?.email);
              set({ searchResults: filtered });
          } catch (e) { console.error(e); }
      },

      addContact: async (email) => {
          const { currentUser } = get();
          if (!currentUser) return;

          await authService.addContact(email);

          // Optimistically update
          set((state) => {
              if (state.friends.some(f => f.id === email)) return {};
              const newFriend: Friend = {
                  id: email,
                  name: email.split('@')[0],
                  image: '',
                  status: 'offline',
                  lastActive: 0,
                  chatHistory: []
              };
              return { 
                  friends: [...state.friends, newFriend],
                  activeChatFriendId: email // Open chat immediately
              };
          });

          // Re-init listeners to subscribe to new friend's status
          setTimeout(() => {
              get().initRealtimeListeners();
          }, 500);
      },

      refreshFriendsActivity: async () => {
          get().initRealtimeListeners();
      },

      openChat: (friendId) => set({ activeChatFriendId: friendId }),

      sendMessage: async (friendId, text) => {
          const { currentUser } = get();
          if (!currentUser) return;

          const newMessage: ChatMessage = {
              id: `msg-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
              senderId: currentUser.email,
              text,
              timestamp: Date.now()
          };

          set((state) => {
              const updatedFriends = state.friends.map(f => {
                  if (f.id === friendId) {
                      return { ...f, chatHistory: [...f.chatHistory, newMessage] };
                  }
                  return f;
              });
              return { friends: updatedFriends };
          });

          await authService.sendChatMessage(currentUser.email, friendId, newMessage);
      },

      startParty: () => set((state) => {
         if (!state.currentUser) return {};
         return {
             partySession: {
                 isActive: true,
                 hostId: 'me',
                 hostName: state.currentUser.name,
                 listeners: state.activeChatFriendId ? [state.activeChatFriendId] : []
             }
         }
      }),

      stopParty: () => set({ partySession: null })
    }),
    {
      name: 'vibestream-storage',
      partialize: (state) => ({ 
        history: state.history, 
        volume: state.volume,
        likedSongs: state.likedSongs,
        userPlaylists: state.userPlaylists,
        currentUser: state.currentUser,
      }), 
    }
  )
);

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { usePlayerStore } from '../store/playerStore';
import { authService } from '../services/auth';
import { getImageUrl, api } from '../services/api';
import { Play, Pause, Clock3, MoreHorizontal, Trash2, Music, ArrowLeft, Search, Plus, CheckCircle2, Download, Heart, Share2 } from 'lucide-react';
import { Song, UserPlaylist } from '../types';

export const PlaylistDetails: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { userPlaylists, playSong, currentSong, isPlaying, removePlaylist, addSongToPlaylist, importPlaylist } = usePlayerStore();
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Song[]>([]);
  const [isSearching, setIsSearching] = useState(false);

  // State for handling fetched shared playlists
  const [viewPlaylist, setViewPlaylist] = useState<UserPlaylist | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  // Check if it's already in my library
  const isMyPlaylist = userPlaylists.some(p => p.id === id);

  useEffect(() => {
      const loadPlaylist = async () => {
          setIsLoading(true);
          // 1. Try finding in local store first
          const localPlaylist = userPlaylists.find(p => p.id === id);
          if (localPlaylist) {
              setViewPlaylist(localPlaylist);
              setIsLoading(false);
              return;
          }

          // 2. If not found, try fetching from global public playlists
          if (id) {
              const publicPlaylist = await authService.getPublicPlaylist(id);
              if (publicPlaylist) {
                  setViewPlaylist(publicPlaylist);
              }
          }
          setIsLoading(false);
      };
      loadPlaylist();
  }, [id, userPlaylists]);

  // Debounced Search for "Add Songs"
  useEffect(() => {
    const timer = setTimeout(async () => {
      if (searchQuery.trim()) {
        setIsSearching(true);
        try {
           const songs = await api.searchSongs(searchQuery);
           setSearchResults(songs.slice(0, 5));
        } catch (e) {
           console.error(e);
        } finally {
            setIsSearching(false);
        }
      } else {
        setSearchResults([]);
      }
    }, 500); 
    return () => clearTimeout(timer);
  }, [searchQuery]);


  if (isLoading) {
      return (
          <div className="flex h-full w-full items-center justify-center bg-[#121212]">
              <div className="w-8 h-8 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
          </div>
      );
  }

  if (!viewPlaylist) {
      return (
          <div className="flex flex-col items-center justify-center h-full text-white">
              <h2 className="text-2xl font-bold mb-4">Playlist not found</h2>
              <button onClick={() => navigate('/library')} className="px-6 py-2 bg-white text-black rounded-full font-bold">Back to Library</button>
          </div>
      );
  }

  const handleDelete = () => {
      if (window.confirm("Are you sure you want to delete this playlist?")) {
          removePlaylist(viewPlaylist.id);
          navigate('/library');
      }
  };

  const handleImport = () => {
      importPlaylist(viewPlaylist);
      alert('Playlist added to your library!');
  };

  const handleShare = () => {
      const url = window.location.href;
      navigator.clipboard.writeText(url).then(() => {
          alert("Link copied to clipboard!");
      });
  };

  const handleAddSong = (song: Song) => {
      addSongToPlaylist(viewPlaylist.id, song);
  };

  const imageUrl = getImageUrl(viewPlaylist.image);

  return (
    <div className="min-h-full pb-32 bg-[#121212] relative">
      {/* Background Gradient based on playlist */}
      <div className="absolute top-0 left-0 right-0 h-[400px] bg-gradient-to-b from-[#404040] to-[#121212] -z-10 opacity-60"></div>

      {/* Header */}
      <div className="sticky top-0 z-30 px-6 py-4 flex items-center justify-between bg-transparent transition-colors">
          <button 
            onClick={() => navigate(-1)} 
            className="w-8 h-8 rounded-full bg-black/40 hover:bg-black/60 flex items-center justify-center text-white backdrop-blur-md"
          >
             <ArrowLeft size={20} />
          </button>

          <div className="flex items-center gap-2">
             <button 
                onClick={handleShare}
                className="w-8 h-8 rounded-full bg-black/40 hover:bg-white/10 flex items-center justify-center text-white backdrop-blur-md transition-colors"
                title="Share Playlist"
             >
                 <Share2 size={16} />
             </button>
            {isMyPlaylist ? (
                <button 
                    onClick={handleDelete}
                    className="w-8 h-8 rounded-full bg-black/40 hover:bg-red-500/80 flex items-center justify-center text-white backdrop-blur-md transition-colors"
                    title="Delete Playlist"
                >
                    <Trash2 size={16} />
                </button>
            ) : (
                 <button 
                    onClick={handleImport}
                    className="flex items-center gap-2 px-4 py-1.5 bg-white text-black rounded-full font-bold text-sm hover:scale-105 transition-transform shadow-lg"
                >
                    <Heart size={16} fill="black" /> Add to Library
                </button>
            )}
          </div>
      </div>

      {/* Playlist Hero */}
      <div className="flex flex-col md:flex-row items-end gap-6 p-6 md:p-8 -mt-10">
        <div className="w-[190px] h-[190px] md:w-[230px] md:h-[230px] shadow-[0_30px_60px_rgba(0,0,0,0.5)] bg-[#282828] flex items-center justify-center overflow-hidden shrink-0 group rounded-md">
             {viewPlaylist.image && (viewPlaylist.image[0].url.includes('unsplash') || viewPlaylist.image[0].url.includes('cloudinary')) ? (
                 <img src={imageUrl} alt={viewPlaylist.title} className="w-full h-full object-cover shadow-2xl" />
             ) : (
                 <Music size={80} className="text-white/20" />
             )}
        </div>
        <div className="flex flex-col gap-2 mb-2 w-full">
            <span className="uppercase text-xs font-bold tracking-wider text-white">Playlist</span>
            <h1 className="text-4xl md:text-7xl lg:text-8xl font-black tracking-tight text-white leading-none break-words line-clamp-2 drop-shadow-lg">{viewPlaylist.title}</h1>
            <p className="text-white/70 text-sm mt-2 line-clamp-2 font-medium">{viewPlaylist.description}</p>
            <div className="flex items-center flex-wrap gap-2 text-sm font-bold text-white mt-2">
                <div className="w-6 h-6 rounded-full bg-white flex items-center justify-center text-[10px] text-black">
                    {viewPlaylist.creator ? viewPlaylist.creator.charAt(0).toUpperCase() : 'U'}
                </div>
                <span className="cursor-pointer hover:underline">{isMyPlaylist ? 'You' : 'Shared User'}</span>
                <span className="text-white/60">• {viewPlaylist.songs.length} songs</span>
            </div>
        </div>
      </div>

      {/* Control Bar */}
      <div className="px-6 md:px-8 py-6 flex items-center gap-8 bg-gradient-to-b from-black/20 to-[#121212]">
