      if (hour >= 5 && hour < 12) query = 'Morning Acoustic';
      else if (hour >= 12 && hour < 17) query = 'Upbeat Pop';
      else query = 'Late Night Vibes';

      try {
        const songs = await api.searchSongs(query);
        // Artificial delay for smoothness if network is too fast (prevents flicker)
        await new Promise(r => setTimeout(r, 400));
        setDaylist(songs);
      } catch (e) {
        console.error(e);
      } finally {
        setIsLoading(false);
      }
    };
    fetchData();
  }, []);

  useEffect(() => {
    // Populate recent with history or default items
    if (history.length > 0) {
      setRecent(history.slice(0, 6));
    } else {
       // Defaults to populate the grid if empty history
       Promise.all([
         api.searchSongs("The Weeknd"),
         api.searchAlbums("Starboy"),
         api.searchSongs("Taylor Swift"),
         api.searchAlbums("1989"),
       ]).then(([songs, albums, songs2, albums2]) => {
          setRecent([...songs.slice(0,1), ...albums.slice(0,1), ...songs2.slice(0,1), ...albums2.slice(0,1)]);
       });
    }
  }, [history]);

  // Scroll listener for header effect (Attached to main container)
  useEffect(() => {
    const main = document.querySelector('main');
    const handleScroll = () => {
        if (main) setIsScrolled(main.scrollTop > 10);
    };
    main?.addEventListener('scroll', handleScroll);
    return () => main?.removeEventListener('scroll', handleScroll);
  }, []);

  const ShortcutCard: React.FC<{ title: string, image?: string, isLikedSongs?: boolean, onClick?: () => void }> = ({ title, image, isLikedSongs = false, onClick }) => (
    <div 
        onClick={onClick}
        className="glass-card flex items-center gap-0 cursor-pointer h-[48px] overflow-hidden group rounded-[4px] bg-[#2A2A2A] hover:bg-[#3E3E3E] transition-colors"
    >
        {isLikedSongs ? (
            <div className="h-full w-[48px] bg-gradient-to-br from-[#450af5] to-[#c4efd9] flex items-center justify-center shrink-0 opacity-100">
                <svg role="img" height="18" width="18" aria-hidden="true" viewBox="0 0 24 24" fill="white"><path d="M15.724 4.22A4.313 4.313 0 0 0 12.192.814a4.269 4.269 0 0 0-3.622 1.13.837.837 0 0 1-1.14 0 4.272 4.272 0 0 0-6.21 5.855l5.916 7.05a1.128 1.128 0 0 0 1.727 0l5.916-7.05a4.228 4.228 0 0 0 .945-3.577z"></path></svg>
            </div>
        ) : (
            <img src={image} className="h-[48px] w-[48px] object-cover shrink-0 shadow-none" alt=""/>
        )}
        <div className="flex flex-1 items-center justify-between pr-2 pl-2 overflow-hidden">
             <span className="font-bold text-[11px] md:text-[13px] leading-tight line-clamp-2 text-white pr-1">{title}</span>
        </div>
    </div>
  );

  const SectionTitle = ({ title }: { title: string }) => (
      <h2 className="text-xl md:text-2xl font-bold mb-4 text-white px-4 hover:underline cursor-pointer tracking-tight">{title}</h2>
  );

  const handleProfileClick = () => {
    if (currentUser) {
        navigate('/profile');
    } else {
        navigate('/login');
    }
  };

  return (
    <div className={`flex flex-col gap-6 min-h-full pb-36 relative bg-black`}>

      {/* Top Header - Fixed Overlapping and Glass Effect */}
      <div className={`px-4 flex items-center justify-start gap-3 sticky top-0 z-50 py-3 transition-all duration-300 ${isScrolled ? 'bg-black border-b border-white/10 shadow-lg' : 'bg-black'}`}>
         {/* Profile Icon */}
         <div 
            onClick={handleProfileClick}
            className="w-8 h-8 rounded-full bg-gradient-to-tr from-[#1DB954] to-[#1ed760] flex items-center justify-center font-bold text-black text-sm shrink-0 cursor-pointer hover:scale-105 transition-transform overflow-hidden shadow-md"
         >
             {currentUser && currentUser.image ? (
                 <img src={currentUser.image} alt="Profile" className="w-full h-full object-cover" />
             ) : (
                 <span className="font-bold">{currentUser ? currentUser.name.charAt(0).toUpperCase() : <UserCircle size={20} />}</span>
             )}
         </div>

         {/* Filter Chips */}
         <div className="flex items-center gap-2 overflow-x-auto no-scrollbar mask-linear-fade">
             <button className="px-4 py-1.5 bg-[#1DB954] text-black rounded-full text-[13px] font-medium transition-transform shadow-sm whitespace-nowrap active:scale-95">All</button>
             <button className="px-4 py-1.5 bg-[#2A2A2A] text-white rounded-full text-[13px] font-medium whitespace-nowrap border border-transparent hover:bg-[#333] active:scale-95">Music</button>
             <button className="px-4 py-1.5 bg-[#2A2A2A] text-white rounded-full text-[13px] font-medium whitespace-nowrap border border-transparent hover:bg-[#333] active:scale-95">Podcasts</button>
         </div>
      </div>

      {/* Grid Shortcuts (Jump back in) */}
      <div className="px-4 mt-2">
          <h2 className="text-2xl font-bold text-white mb-4">Jump back in</h2>
          <div className="grid grid-cols-2 gap-2">
            <ShortcutCard title="Liked Songs" isLikedSongs onClick={() => navigate('/library')} />
            {isLoading || recent.length === 0 ? (
                // Skeleton Shortcuts
                Array(5).fill(0).map((_, i) => <SkeletonShortcut key={i} />)
            ) : (
                recent.slice(0, 5).map((item, idx) => (
                    <ShortcutCard 
                        key={item.id + idx} 
                        title={item.name} 
                        image={getImageUrl(item.image)}
                        onClick={() => item.type === 'song' ? playSong(item as Song, [item as Song]) : navigate(`/album/${item.id}`)}
                    />
                ))
            )}
          </div>
      </div>

      {/* Recommended Section */}
      <section className="mt-2">
        <SectionTitle title="Made For You" />
        <div className="flex overflow-x-auto gap-4 pb-4 no-scrollbar px-4 snap-x">
            {isLoading ? (
                 Array(6).fill(0).map((_, i) => <SkeletonCard key={i} />)
            ) : (
                 daylist.map((item, i) => (
                    <div key={i} className="snap-start">
                        <SongCard item={item} onPlay={() => playSong(item, daylist)} />
                    </div>
                 ))
            )}
        </div>
      </section>

      {/* Popular Artists */}
       <section>
        <SectionTitle title="Your favorite artists" />
        <div className="flex overflow-x-auto gap-4 pb-4 no-scrollbar px-4 snap-x">
            {isLoading ? (
                 Array(6).fill(0).map((_, i) => <SkeletonCard key={i} round={true} />)
            ) : (
                 daylist.slice(0,6).map((item, i) => (
                    <div key={i} className="snap-start">
                        <SongCard item={item} round={true} />
                    </div>
                 ))
            )}
        </div>
      </section>

       {/* Recently Played */}
      <section>
        <SectionTitle title="Recently played" />
        <div className="flex overflow-x-auto gap-4 pb-4 no-scrollbar px-4 snap-x">
            {isLoading ? (
                 Array(4).fill(0).map((_, i) => <SkeletonCard key={i} />)
            ) : recent.length > 0 ? (
                recent.map((item, i) => (
                    <div key={i} className="snap-start">
                        <SongCard item={item} onPlay={() => item.type === 'song' && playSong(item as Song, [item as Song])} />
                    </div>
                ))
            ) : (
                 <div className="text-[#B3B3B3] text-sm px-4 h-[100px] flex items-center">Play some music to see it here.</div>
            )}
        </div>
      </section>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { usePlayerStore } from '../store/playerStore';
import { authService } from '../services/auth';
import { getImageUrl, api } from '../services/api';
import { Play, Pause, Clock3, MoreHorizontal, Trash2, Music, ArrowLeft, Search, Plus, CheckCircle2, Download, Heart, Share2 } from 'lucide-react';
import { Song, UserPlaylist } from '../types';

export const PlaylistDetails: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { userPlaylists, playSong, currentSong, isPlaying, removePlaylist, addSongToPlaylist, importPlaylist } = usePlayerStore();

  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Song[]>([]);
  const [isSearching, setIsSearching] = useState(false);

  const [viewPlaylist, setViewPlaylist] = useState<UserPlaylist | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isScrolled, setIsScrolled] = useState(false);

  const isMyPlaylist = userPlaylists.some(p => p.id === id);

  // Scroll listener attached to MAIN container to fix overlapping issues
  useEffect(() => {
    const main = document.querySelector('main');
    const handleScroll = () => {
        if (main) setIsScrolled(main.scrollTop > 100);
    };
    main?.addEventListener('scroll', handleScroll);
    return () => main?.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
      const loadPlaylist = async () => {
          setIsLoading(true);
          // 1. Try finding in local store first
          const localPlaylist = userPlaylists.find(p => p.id === id);
          if (localPlaylist) {
              setViewPlaylist(localPlaylist);
              setIsLoading(false);
              return;
          }

          // 2. If not found, try fetching from global public playlists
          if (id) {
              const publicPlaylist = await authService.getPublicPlaylist(id);
              if (publicPlaylist) {
                  setViewPlaylist(publicPlaylist);
              }
          }
          setIsLoading(false);
      };
      loadPlaylist();
  }, [id, userPlaylists]);

  // Debounced Search for "Add Songs"
  useEffect(() => {
    const timer = setTimeout(async () => {
      if (searchQuery.trim()) {
        setIsSearching(true);
        try {
           const songs = await api.searchSongs(searchQuery);
           setSearchResults(songs.slice(0, 5));
        } catch (e) {
           console.error(e);
        } finally {
            setIsSearching(false);
        }
      } else {
        setSearchResults([]);
      }
    }, 500); 
    return () => clearTimeout(timer);
  }, [searchQuery]);


  if (isLoading) {
      return (
          <div className="flex h-full w-full items-center justify-center bg-[#121212]">
              <div className="w-8 h-8 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
          </div>
      );
  }

  if (!viewPlaylist) {
      return (
          <div className="flex flex-col items-center justify-center h-full text-white">
              <h2 className="text-2xl font-bold mb-4">Playlist not found</h2>
              <button onClick={() => navigate('/library')} className="px-6 py-2 bg-white text-black rounded-full font-bold">Back to Library</button>
          </div>
      );
  }

  const handleDelete = () => {
      if (window.confirm("Are you sure you want to delete this playlist?")) {
          removePlaylist(viewPlaylist.id);
          navigate('/library');
      }
  };

  const handleImport = () => {
      importPlaylist(viewPlaylist);
      alert('Playlist added to your library!');
  };

  const handleShare = () => {
      const url = window.location.href;
      navigator.clipboard.writeText(url).then(() => {
          alert("Link copied to clipboard!");
      });
  };

  const handleAddSong = (song: Song) => {
      addSongToPlaylist(viewPlaylist.id, song);
  };

  const imageUrl = getImageUrl(viewPlaylist.image);

  return (
    <div className="min-h-full pb-32 bg-[#121212] relative isolate">
      {/* Background Gradient based on playlist */}
      <div className="absolute top-0 left-0 right-0 h-[500px] bg-gradient-to-b from-[#505050] via-[#2a2a2a] to-[#121212] -z-10 opacity-100 transition-all duration-700"></div>

      {/* Sticky Header */}
      <div className={`sticky top-0 z-50 h-[64px] px-6 flex items-center justify-between transition-colors duration-200 ${isScrolled ? 'bg-[#121212] border-b border-[#282828]' : 'bg-transparent'}`}>
          <div className="flex items-center gap-4">
              <button 
                onClick={() => navigate(-1)} 
                className="w-8 h-8 rounded-full bg-black/40 hover:bg-black/60 flex items-center justify-center text-white transition-all active:scale-95"
              >
                 <ArrowLeft size={20} />
              </button>
              <span className={`font-bold text-lg text-white transition-opacity duration-300 ${isScrolled ? 'opacity-100' : 'opacity-0'}`}>
                  {viewPlaylist.title}
              </span>
          </div>

          <div className="flex items-center gap-3">
             <button 
                onClick={handleShare}
                className="flex items-center gap-2 px-3 py-1.5 rounded-full bg-black/20 hover:bg-white/10 text-white text-xs font-bold border border-white/10 transition-all"
                title="Copy Link"
             >
                 <Share2 size={14} />
                 <span className="hidden sm:block">Share</span>
             </button>
            {isMyPlaylist ? (
                <button 
                    onClick={handleDelete}
                    className="w-9 h-9 rounded-full bg-black/20 hover:bg-red-500/20 hover:text-red-500 flex items-center justify-center text-white/70 transition-colors"
                    title="Delete Playlist"
                >
                    <Trash2 size={18} />
                </button>
            ) : (
                 <button 
                    onClick={handleImport}
                    className="flex items-center gap-2 px-4 py-2 bg-white text-black rounded-full font-bold text-xs md:text-sm hover:scale-105 transition-transform shadow-lg"
                >
                    <Heart size={16} fill={userPlaylists.some(p => p.id === viewPlaylist.id) ? "black" : "none"} /> 
                    {userPlaylists.some(p => p.id === viewPlaylist.id) ? 'Saved' : 'Save'}
                </button>
            )}
          </div>
      </div>

      {/* Hero Content */}
      <div className="flex flex-col md:flex-row items-end gap-6 p-6 md:p-10 pt-2">
        <div className="w-[180px] h-[180px] md:w-[240px] md:h-[240px] shadow-[0_20px_50px_rgba(0,0,0,0.5)] bg-[#282828] flex items-center justify-center overflow-hidden shrink-0 group rounded-lg relative">
             {viewPlaylist.image && (viewPlaylist.image[0].url.includes('unsplash') || viewPlaylist.image[0].url.includes('cloudinary')) ? (
                 <img src={imageUrl} alt={viewPlaylist.title} className="w-full h-full object-cover shadow-2xl" />
             ) : (
                 <div className="flex flex-col items-center gap-2">
                    <Music size={60} className="text-white/20" />
                 </div>
             )}
        </div>
        <div className="flex flex-col gap-2 mb-2 w-full min-w-0">
            <span className="uppercase text-xs font-bold tracking-wider text-white hidden md:block">Playlist</span>
            <h1 className="text-4xl md:text-6xl lg:text-7xl font-black tracking-tight text-white leading-none break-words drop-shadow-lg line-clamp-2 py-2">{viewPlaylist.title}</h1>
            <p className="text-white/70 text-sm font-medium line-clamp-2 max-w-2xl">{viewPlaylist.description}</p>
            <div className="flex items-center flex-wrap gap-2 text-sm font-bold text-white mt-4">
                <div className="flex items-center gap-2 bg-black/20 px-2 py-1 rounded-full">
                    <div className="w-5 h-5 rounded-full bg-gradient-to-br from-green-400 to-blue-500 flex items-center justify-center text-[10px] text-white shadow-sm">
                        {viewPlaylist.creator ? viewPlaylist.creator.charAt(0).toUpperCase() : 'U'}
                    </div>
                    <span className="hover:underline cursor-pointer text-xs">{isMyPlaylist ? 'You' : 'Shared User'}</span>
                </div>
                <span className="text-white/60">•</span>
                <span className="text-white/90">{viewPlaylist.songs.length} songs</span>
            </div>
        </div>
      </div>

      {/* Action Buttons Row */}
      <div className="px-6 md:px-10 py-6 flex items-center gap-6 bg-[#121212]/30">
         {viewPlaylist.songs.length > 0 && (
             <button 
                onClick={() => playSong(viewPlaylist.songs[0], viewPlaylist.songs)}
                className="w-14 h-14 bg-[#1DB954] hover:bg-[#1ed760] rounded-full flex items-center justify-center hover:scale-105 active:scale-95 transition-all shadow-[0_8px_20px_rgba(0,0,0,0.3)]"
             >
                 {isPlaying && viewPlaylist.songs.some(s => s.id === currentSong?.id) ? (
                     <Pause size={28} fill="black" className="text-black" />
                 ) : (
                     <Play size={28} fill="black" className="ml-1 text-black" />
                 )}
             </button>
         )}
         <button className="text-white/50 hover:text-white transition-colors">
             <MoreHorizontal size={32} />
         </button>
      </div>

      {/* Songs List */}
      <div className="px-2 md:px-10 min-h-[300px] bg-[#121212]">
        {/* List Header - Sticky below main nav */}
        {viewPlaylist.songs.length > 0 && (
            <div className="grid grid-cols-[auto_1fr_auto] md:grid-cols-[16px_1fr_1fr_auto] gap-4 text-[#B3B3B3] text-xs font-medium border-b border-[#282828] pb-2 mb-4 px-4 uppercase tracking-wider sticky top-[64px] bg-[#121212] z-40 py-3 shadow-sm">
                <span className="text-center w-8 md:w-auto">#</span>
                <span>Title</span>
                <span className="hidden md:block">Album</span>
                <div className="flex justify-end"><Clock3 size={16} /></div>
            </div>
        )}

        {/* Empty State */}
        {viewPlaylist.songs.length === 0 && (
            <div className="flex flex-col items-center justify-center py-20 text-white/40 border-t border-white/5 mt-4">
                <div className="w-20 h-20 bg-[#1A1A1A] rounded-full flex items-center justify-center mb-6">
                    <Music size={40} className="opacity-50" />
                </div>
                <h3 className="text-xl font-bold text-white mb-2">It feels empty here</h3>
                <p className="max-w-xs text-center text-sm">Find songs you love to build your perfect playlist.</p>
            </div>
        )}

        <div className="flex flex-col pb-10">
            {viewPlaylist.songs.map((song, index) => {
                const isCurrent = currentSong?.id === song.id;
                return (
                    <div 
                        key={`${song.id}-${index}`}
                        onClick={() => playSong(song, viewPlaylist.songs)}
                        className={`group grid grid-cols-[auto_1fr_auto] md:grid-cols-[16px_1fr_1fr_auto] gap-4 items-center px-3 py-2.5 rounded-lg cursor-pointer transition-colors ${isCurrent ? 'bg-white/10' : 'hover:bg-white/5'} animate-in fade-in slide-in-from-bottom-2`}
                        style={{ animationDelay: `${index * 30}ms` }}
                    >
                        {/* Number / Play Icon */}
                        <div className="w-8 md:w-auto flex justify-center items-center text-sm font-mono text-[#B3B3B3]">
                            <span className={`group-hover:hidden ${isCurrent ? 'text-[#1DB954]' : ''}`}>{index + 1}</span>
                            <Play size={12} fill="white" className={`hidden group-hover:block text-white`} />
                            {isCurrent && <img src="https://open.spotifycdn.com/cdn/images/equaliser-animated-green.f93a2ef4.gif" className="h-3 w-3 absolute ml-4 group-hover:hidden" alt="playing"/>}
                        </div>

                        <div className="flex items-center gap-3 overflow-hidden">
                            <img src={getImageUrl(song.image)} alt="" className="w-10 h-10 rounded-[4px] object-cover shadow-sm shrink-0" />
                            <div className="flex flex-col truncate">
                                <span className={`font-medium text-[15px] truncate ${isCurrent ? 'text-[#1DB954]' : 'text-white'}`}>{song.name}</span>
                                <span className="text-xs text-[#B3B3B3] group-hover:text-white truncate transition-colors">{song.artists?.primary?.[0]?.name || "Unknown"}</span>
                            </div>
                        </div>

                        <span className="hidden md:block text-sm text-[#B3B3B3] truncate group-hover:text-white transition-colors">{song.album?.name || "Single"}</span>

                        <div className="flex items-center justify-end gap-4 min-w-[60px]">
                            <button className="opacity-0 group-hover:opacity-100 transition-opacity text-[#B3B3B3] hover:text-white hidden md:block">
                                <Heart size={16} />
                            </button>
                            <span className="text-sm font-mono text-[#B3B3B3]">
                                {Math.floor(parseInt(song.duration) / 60)}:{(parseInt(song.duration) % 60).toString().padStart(2, '0')}
                            </span>
                        </div>
                    </div>
                );
            })}
        </div>

        {/* --- ADD SONGS SECTION (Only if user owns playlist) --- */}
        {isMyPlaylist && (
            <div className="mt-8 mb-16 border-t border-white/10 pt-8">
                <div className="flex flex-col gap-4 mb-6">
                    <h2 className="text-xl md:text-2xl font-bold text-white">Let's find something for your playlist</h2>
                    <div className="relative max-w-md">
                        <Search size={20} className="absolute left-3 top-1/2 -translate-y-1/2 text-[#B3B3B3]" />
                        <input 
                            type="text" 
                            placeholder="Search for songs" 
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            className="w-full bg-[#2A2A2A] text-white pl-10 pr-10 py-3 rounded-md focus:outline-none focus:bg-[#333] focus:ring-1 focus:ring-white/20 transition-all placeholder-[#B3B3B3] text-sm font-medium"
                        />
                        {searchQuery && (
                            <button onClick={() => setSearchQuery('')} className="absolute right-3 top-1/2 -translate-y-1/2">
                                 {isSearching ? <div className="w-4 h-4 border-2 border-white/20 border-t-white rounded-full animate-spin"></div> : <div className="text-white/50 hover:text-white">✕</div>}
                            </button>
                        )}
                    </div>
                </div>

                <div className="flex flex-col gap-1">
                    {searchResults.map((song) => {
                        const isAdded = viewPlaylist.songs.some(s => s.id === song.id);
                        return (
                            <div key={song.id} className="flex items-center justify-between p-3 hover:bg-[#2A2A2A] rounded-lg group transition-colors animate-in fade-in slide-in-from-bottom-2 duration-300">
                                <div className="flex items-center gap-3 overflow-hidden">
                                    <img src={getImageUrl(song.image)} className="w-10 h-10 object-cover rounded shadow-sm" alt="" />
                                    <div className="flex flex-col truncate">
                                        <span className="text-white font-medium text-sm truncate">{song.name}</span>
                                        <span className="text-[#B3B3B3] text-xs truncate">{song.artists?.primary?.[0]?.name}</span>
                                    </div>
                                </div>
                                <button 
                                    onClick={() => !isAdded && handleAddSong(song)}
                                    disabled={isAdded}
                                    className={`px-4 py-1.5 rounded-full border text-xs font-bold transition-all ${isAdded ? 'border-transparent text-white/50' : 'border-[#727272] text-white hover:border-white hover:scale-105'}`}
                                >
                                    {isAdded ? 'Added' : 'Add'}
                                </button>
                            </div>
                        )
                    })}
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { usePlayerStore } from '../store/playerStore';
import { ArrowLeft, Play, Pause, Clock3, Heart, Download, ListFilter, Search, CheckCircle2 } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { getImageUrl } from '../services/api';

export const LikedSongs: React.FC = () => {
