      </section>

       {/* Recently Played */}
      <section>
        <SectionTitle title="Recently played" />
        <div className="flex overflow-x-auto gap-4 pb-4 no-scrollbar px-4 snap-x">
            {isLoading ? (
                 Array(4).fill(0).map((_, i) => <SkeletonCard key={i} />)
