                                <div className="w-[120px] h-[120px] rounded-full overflow-hidden bg-[#282828] shadow-lg group-hover:shadow-2xl transition-all">
                                    <img src={getImageUrl(artist.image)} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500" alt="" />
                                </div>
                                <span className="font-bold text-white text-center text-sm truncate w-full group-hover:underline">{artist.name}</span>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* Albums Section */}
            {results.albums.length > 0 && (
                 <div className="mb-6 animate-in fade-in slide-in-from-bottom-3 duration-300 delay-150">
                    <h2 className="px-4 text-white font-bold mb-3 text-xl">Albums</h2>
                    <div className="flex flex-col gap-1">
                    {results.albums.slice(0, 3).map(album => (
                        <div key={album.id} className="flex items-center gap-3 px-4 py-2 hover:bg-[#2A2A2A] cursor-pointer group transition-colors" onClick={() => navigate(`/album/${album.id}`)}>
                            <div className="w-12 h-12 shrink-0">
                                <img src={getImageUrl(album.image)} className="w-full h-full rounded-[4px] object-cover shadow-sm" alt="" />
                            </div>
                            <div className="flex-1 min-w-0">
                                <div className="text-white font-medium truncate text-[15px] group-hover:text-[#1DB954] transition-colors">{album.name}</div>
                                <div className="text-[#B3B3B3] text-sm truncate">Album • {album.year}</div>
                            </div>
                            <ChevronRight size={20} className="text-[#333] group-hover:text-white" />
                        </div>
                    ))}
                    </div>
                 </div>
            )}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
