export const Search: React.FC = () => {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<{ songs: Song[], albums: Album[], artists: Artist[] }>({ songs: [], albums: [], artists: [] });
  const [isLoading, setIsLoading] = useState(false);
  const [suggestions, setSuggestions] = useState<string[]>([]);

  const { playSong, likedSongs, toggleLike } = usePlayerStore();
  const navigate = useNavigate();

  // AbortController to handle race conditions
  const abortControllerRef = useRef<AbortController | null>(null);

  useEffect(() => {
    // Cancel any ongoing fetch if query changes
    if (abortControllerRef.current) {
        abortControllerRef.current.abort();
    }

    if (!query.trim()) {
        setResults({ songs: [], albums: [], artists: [] });
        setSuggestions([]);
        setIsLoading(false);
        return;
    }

    setIsLoading(true);

    const timer = setTimeout(async () => {
        abortControllerRef.current = new AbortController();
        try {
           const [songs, albums, artists] = await Promise.all([
              api.searchSongs(query),
              api.searchAlbums(query),
              api.searchArtists(query)
           ]);

           // Only update if not aborted
           if (!abortControllerRef.current?.signal.aborted) {
               setResults({ songs, albums, artists });

               // Generate Related Keywords from results
               // Logic: Take song titles, lowercase them, remove special chars, pick top 4 unique ones
               const rawTitles = songs.map(s => s.name.toLowerCase());
               // Also add query + ' song' or artist names
               const artistNames = artists.slice(0, 2).map(a => a.name.toLowerCase());

               const derivedSuggestions = Array.from(new Set([
                   query.toLowerCase(), // The query itself
                   ...rawTitles.filter(t => t.includes(query.toLowerCase()) && t !== query.toLowerCase()), // Titles containing query
                   ...artistNames,
                   ...rawTitles // Fallback to just titles
               ])).slice(0, 4); // Take top 4

               setSuggestions(derivedSuggestions);
           }
        } catch (e: any) {
            if (e.name !== 'AbortError') {
                console.error(e);
            }
        } finally {
            if (!abortControllerRef.current?.signal.aborted) {
                setIsLoading(false);
            }
        }
    }, 300); // Faster debounce

    return () => clearTimeout(timer);
  }, [query]);

  const clearSearch = () => {
    setQuery('');
    setResults({ songs: [], albums: [], artists: [] });
    setSuggestions([]);
    setIsLoading(false);
  };

  const ResultSkeleton = () => (
      <div className="flex items-center gap-3 px-4 py-2.5 animate-pulse">
          <div className="w-12 h-12 bg-white/10 rounded-md shrink-0"></div>
          <div className="flex-1 space-y-2 py-1">
              <div className="h-4 bg-white/10 rounded w-1/3"></div>
              <div className="h-3 bg-white/5 rounded w-1/4"></div>
          </div>
      </div>
  );

  return (
    <div className="flex flex-col min-h-full pb-32 bg-black">

      {/* Search Header */}
      <div className="sticky top-0 bg-[#121212] z-30 px-4 py-3 border-b border-white/5">
         <div className="flex items-center gap-3">
             <button onClick={() => navigate(-1)} className="text-white hover:bg-white/10 p-2 rounded-full transition-colors active:scale-95 md:hidden">
                <ArrowLeft size={24} />
             </button>
             <div className="flex-1 relative group">
                {/* Dark Input Field */}
                <input 
                  type="text"
                  className="w-full bg-[#242424] text-white rounded-md py-2.5 pl-10 pr-10 focus:outline-none focus:bg-[#2A2A2A] placeholder-[#777] font-medium text-[16px] transition-all"
                  placeholder="What do you want to listen to?"
                  value={query}
                  onChange={(e) => setQuery(e.target.value)}
                  autoFocus={false}
                />
                 <div className="absolute inset-y-0 left-3 flex items-center pointer-events-none">
                     <SearchIcon size={18} className="text-[#B3B3B3]" />
                </div>
                {(query || isLoading) && (
                    <div className="absolute right-3 top-1/2 -translate-y-1/2 flex items-center">
                         {isLoading ? (
                             <Loader2 size={18} className="text-[#B3B3B3] animate-spin" />
                         ) : (
                             <button onClick={clearSearch} className="text-[#B3B3B3] hover:text-white p-1">
                                 <X size={18} />
                             </button>
                         )}
                    </div>
                )}
             </div>
         </div>
      </div>

      {/* Browse All (Initial State) */}
      {!query && (
         <div className="p-4">
             <h2 className="text-white font-bold text-lg mb-4">Browse all</h2>
             <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-5 gap-4">
                 {BROWSE_CATEGORIES.map((cat, idx) => (
                     <div 
                        key={idx} 
                        className={`${cat.color} aspect-[1.6/1] rounded-lg p-4 relative overflow-hidden cursor-pointer hover:opacity-90 transition-opacity`}
                        onClick={() => setQuery(cat.title)} 
                     >
                         <h3 className="text-white font-bold text-xl md:text-2xl break-words max-w-[80%] relative z-10 leading-tight">
                            {cat.title}
                         </h3>
                         <div className="absolute -bottom-2 -right-4 w-20 h-20 bg-black/20 rotate-[25deg] shadow-lg rounded-md flex items-center justify-center">
                         </div>
                     </div>
                 ))}
             </div>
         </div>
      )}

      {/* Loading State Skeleton */}
      {isLoading && !results.songs.length && (
          <div className="flex flex-col w-full pt-2">
              {[1,2,3,4,5].map(i => <ResultSkeleton key={i} />)}
          </div>
      )}

      {/* Results */}
      {query && (
        <div className="flex flex-col w-full pb-8">

            {/* 1. Related Keywords (Suggestions) */}
            {suggestions.length > 0 && (
                <div className="flex flex-col mb-2">
                    {suggestions.map((suggestion, idx) => (
                        <div 
                            key={idx}
                            onClick={() => setQuery(suggestion)}
                            className="flex items-center justify-between px-4 py-3.5 hover:bg-[#1A1A1A] active:bg-[#222] cursor-pointer transition-colors border-b border-white/5 last:border-0"
                        >
                            <div className="flex items-center gap-4">
                                <SearchIcon size={20} className="text-[#B3B3B3]" />
                                <span className="text-white text-[15px]">{suggestion}</span>
                            </div>
                            <ArrowUpLeft size={18} className="text-[#555] rotate-45" />
                        </div>
                    ))}
                </div>
            )}

            {/* 2. Songs List */}
            {results.songs.length > 0 && (
                <div className="animate-in fade-in slide-in-from-bottom-3 duration-300 delay-75">
                     {results.songs.slice(0, 15).map((song) => {
                         const isLiked = likedSongs.some(s => s.id === song.id);
                         const artistName = song.artists?.primary?.[0]?.name || "Unknown";

                         return (
                             <div 
                                key={song.id} 
                                className="flex items-center gap-3 px-4 py-2 hover:bg-[#1A1A1A] cursor-pointer group transition-colors" 
                                onClick={() => playSong(song, results.songs)}
                             >
                                 <div className="w-12 h-12 shrink-0 relative">
                                    <img src={getImageUrl(song.image)} className="w-full h-full rounded-[4px] object-cover" alt="" />
                                 </div>
                                 <div className="flex-1 min-w-0 flex flex-col justify-center gap-0.5">
                                     <div className={`font-medium truncate text-[16px] text-white ${isLiked ? 'text-[#1DB954]' : ''}`}>{song.name}</div>
                                     <div className="text-[#B3B3B3] text-sm truncate flex items-center gap-1">
                                        {/* Explicit Tag Simulation */}
                                        {song.name.toLowerCase().includes('explicit') && (
                                            <span className="bg-[#B3B3B3] text-black text-[9px] px-1 rounded-[2px] font-bold">E</span>
                                        )}
                                        <span>Song • {artistName}</span>
                                     </div>
                                 </div>

                                 <div className="flex items-center gap-4">
                                     <button 
                                        className="text-[#B3B3B3] hover:text-white transition-transform active:scale-90" 
                                        onClick={(e) => { e.stopPropagation(); toggleLike(song); }}
                                     >
                                        {isLiked ? (
                                            <CheckCircle2 size={22} className="text-[#1DB954] fill-[#1DB954] text-black" />
                                        ) : (
                                            <PlusCircle size={22} />
                                        )}
                                     </button>
                                     <button className="text-[#B3B3B3] hover:text-white" onClick={(e) => e.stopPropagation()}>
                                         <MoreVertical size={20} />
                                     </button>
                                 </div>
                             </div>
                         );
                     })}
                </div>
            )}

            {/* No Results */}
            {!isLoading && results.songs.length === 0 && suggestions.length === 0 && (
                <div className="flex flex-col items-center justify-center pt-20 text-[#777]">
                    <div className="w-20 h-20 bg-[#1A1A1A] rounded-full flex items-center justify-center mb-4">
                        <SearchIcon size={40} className="opacity-50"/>
                    </div>
                    <h3 className="text-white font-bold text-lg">No results found</h3>
                    <p className="text-sm mt-2">Try searching for a different song or artist.</p>
                </div>
            )}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { usePlayerStore } from '../store/playerStore';
import { authService } from '../services/auth';
import { getImageUrl, api } from '../services/api';
import { Play, Pause, Clock3, MoreHorizontal, Trash2, Music, ArrowLeft, Search, Plus, CheckCircle2, Download, Heart, Share2, Check } from 'lucide-react';
import { Song, UserPlaylist } from '../types';

export const PlaylistDetails: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { userPlaylists, playSong, currentSong, isPlaying, removePlaylist, addSongToPlaylist, importPlaylist } = usePlayerStore();

  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Song[]>([]);
  const [isSearching, setIsSearching] = useState(false);

  const [viewPlaylist, setViewPlaylist] = useState<UserPlaylist | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isScrolled, setIsScrolled] = useState(false);
  const [shareFeedback, setShareFeedback] = useState(false);

  const isMyPlaylist = userPlaylists.some(p => p.id === id);

  // Scroll listener attached to MAIN container to fix overlapping issues
  useEffect(() => {
    const main = document.querySelector('main');
    const handleScroll = () => {
        if (main) setIsScrolled(main.scrollTop > 100);
    };
    main?.addEventListener('scroll', handleScroll);
    return () => main?.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
      const loadPlaylist = async () => {
          setIsLoading(true);
          // 1. Try finding in local store first
          const localPlaylist = userPlaylists.find(p => p.id === id);
          if (localPlaylist) {
              setViewPlaylist(localPlaylist);
              setIsLoading(false);
              return;
          }

          // 2. If not found, try fetching from global public playlists
          if (id) {
              const publicPlaylist = await authService.getPublicPlaylist(id);
              if (publicPlaylist) {
                  setViewPlaylist(publicPlaylist);
              }
          }
          setIsLoading(false);
      };
      loadPlaylist();
  }, [id, userPlaylists]);

  // Debounced Search for "Add Songs"
  useEffect(() => {
    const timer = setTimeout(async () => {
      if (searchQuery.trim()) {
        setIsSearching(true);
        try {
           const songs = await api.searchSongs(searchQuery);
           setSearchResults(songs.slice(0, 5));
        } catch (e) {
           console.error(e);
        } finally {
            setIsSearching(false);
        }
      } else {
        setSearchResults([]);
      }
    }, 500); 
    return () => clearTimeout(timer);
  }, [searchQuery]);


  if (isLoading) {
      return (
          <div className="flex h-full w-full items-center justify-center bg-[#121212]">
              <div className="w-8 h-8 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
          </div>
      );
  }

  if (!viewPlaylist) {
      return (
          <div className="flex flex-col items-center justify-center h-full text-white">
              <h2 className="text-2xl font-bold mb-4">Playlist not found</h2>
              <button onClick={() => navigate('/library')} className="px-6 py-2 bg-white text-black rounded-full font-bold">Back to Library</button>
          </div>
      );
  }

  const handleDelete = () => {
      if (window.confirm("Are you sure you want to delete this playlist?")) {
          removePlaylist(viewPlaylist.id);
          navigate('/library');
      }
  };

  const handleImport = () => {
      importPlaylist(viewPlaylist);
      alert('Playlist added to your library!');
  };

  const handleShare = () => {
      const url = window.location.href;
      navigator.clipboard.writeText(url).then(() => {
          setShareFeedback(true);
          setTimeout(() => setShareFeedback(false), 2000);
      }).catch(err => {
          console.error("Failed to copy", err);
      });
  };

  const handleAddSong = (song: Song) => {
      addSongToPlaylist(viewPlaylist.id, song);
  };

  const imageUrl = getImageUrl(viewPlaylist.image);

  return (
    <div className="min-h-full pb-32 bg-[#121212] relative isolate">
      {/* Background Gradient based on playlist */}
      <div className="absolute top-0 left-0 right-0 h-[500px] bg-gradient-to-b from-[#505050] via-[#2a2a2a] to-[#121212] -z-10 opacity-100 transition-all duration-700"></div>

      {/* Sticky Header */}
      <div className={`sticky top-0 z-50 h-[64px] px-6 flex items-center justify-between transition-colors duration-200 ${isScrolled ? 'bg-[#121212] border-b border-[#282828]' : 'bg-transparent border-b border-transparent'}`}>
          <div className="flex items-center gap-4">
              <button 
                onClick={() => navigate(-1)} 
                className="w-8 h-8 rounded-full bg-black/40 hover:bg-black/60 flex items-center justify-center text-white transition-all active:scale-95"
              >
                 <ArrowLeft size={20} />
              </button>
              <span className={`font-bold text-lg text-white transition-opacity duration-300 ${isScrolled ? 'opacity-100' : 'opacity-0'}`}>
                  {viewPlaylist.title}
              </span>
          </div>

          <div className="flex items-center gap-3">
             <button 
                onClick={handleShare}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-xs font-bold border transition-all ${
                    shareFeedback 
                    ? 'bg-green-500 border-green-500 text-black' 
                    : 'bg-black/20 hover:bg-white/10 text-white border-white/10'
                }`}
                title="Copy Link"
             >
                 {shareFeedback ? <Check size={14} strokeWidth={3} /> : <Share2 size={14} />}
                 <span className="hidden sm:block">{shareFeedback ? 'Copied' : 'Share'}</span>
             </button>
