import React from 'react';
import { Play, BarChart2 } from 'lucide-react';
import { SearchResult } from '../types';
import { getImageUrl } from '../services/api';
import { useNavigate } from 'react-router-dom';

interface SongCardProps {
  item: SearchResult;
  onPlay?: () => void;
  subtitle?: string;
  round?: boolean;
}

export const SongCard: React.FC<SongCardProps> = ({ item, onPlay, subtitle, round = false }) => {
  const navigate = useNavigate();
  const imageUrl = getImageUrl(item.image);

  const handleClick = () => {
    if (item.type === 'album') {
      navigate(`/album/${item.id}`);
    } else if (item.type === 'artist') {
      navigate(`/artist/${item.id}`, { state: { artist: item } });
    } else if (item.type === 'song' && onPlay) {
      onPlay();
    }
  };

  const handlePlayClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (onPlay) onPlay();
  };

  let safeSubtitle = subtitle;
  if (!safeSubtitle) {
      if (item.type === 'song') {
          safeSubtitle = item.artists?.primary?.[0]?.name || 'Unknown Unit';
      } else if (item.type === 'album') {
          safeSubtitle = `ALBUM • ${item.artists?.primary?.[0]?.name}`;
      } else if (item.type === 'artist') {
          safeSubtitle = 'ARTIST';
      } else if (item.type === 'playlist') {
          safeSubtitle = item.subtitle || 'PLAYLIST';
      }
  }

  const displayTitle = item.type === 'playlist' ? item.title : item.name;

  return (
    <div 
      onClick={handleClick}
      className="group relative bg-[#0f0f0f] hover:bg-[#161616] p-3 transition-all duration-200 cursor-pointer w-[160px] md:w-[180px] shrink-0 border border-white/5 hover:border-accent/50 clip-angle-sm"
    >
      {/* Tech Corner Markers */}
      <div className="absolute top-0 left-0 w-2 h-2 border-l border-t border-white/20 group-hover:border-accent transition-colors"></div>
      <div className="absolute bottom-0 right-0 w-2 h-2 border-r border-b border-white/20 group-hover:border-accent transition-colors"></div>

      <div className={`relative w-full aspect-square mb-3 overflow-hidden ${round ? 'rounded-full border-2 border-white/10' : 'clip-angle-sm'}`}>
        <img 
          src={imageUrl} 
          alt={displayTitle} 
          className={`w-full h-full object-cover transition-all duration-500 filter ${round ? '' : 'grayscale-[30%] contrast-125'} group-hover:grayscale-0 group-hover:scale-105`}
          loading="lazy"
        />

        {/* Play Overlay - HUD Style */}
        {!round && item.type !== 'artist' && (
          <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center backdrop-blur-[1px]">
             <button 
                onClick={handlePlayClick}
                className="w-12 h-12 bg-accent text-white flex items-center justify-center clip-angle-sm hover:scale-110 active:scale-95 transition-transform shadow-[0_0_15px_rgba(255,0,60,0.6)]"
              >
                <Play size={20} fill="white" className="ml-1" />
              </button>
          </div>
        )}

        {/* Scanning Line Effect on Hover */}
        <div className="absolute inset-0 bg-gradient-to-b from-transparent via-accent/10 to-transparent translate-y-[-100%] group-hover:translate-y-[100%] transition-transform duration-700 pointer-events-none"></div>
      </div>

      <div className="flex flex-col gap-1 min-h-[48px]">
        <h3 className="text-white font-bold truncate text-[14px] leading-tight font-display tracking-wide uppercase group-hover:text-accent transition-colors">
          {displayTitle}
        </h3>
        <p className="text-secondary text-[10px] truncate font-mono uppercase tracking-wider flex items-center gap-1">
          {item.type === 'song' && <BarChart2 size={10} />}
          {safeSubtitle}
        </p>
      </div>
    </div>
  );
};

import React, { useRef, useEffect, useState } from 'react';
import { Play, Pause, SkipBack, SkipForward, ChevronDown, MoreHorizontal, Download, ListMusic, Heart, Loader2, Shuffle, Repeat, Mic2, Plus, Minimize2, Radio, Activity } from 'lucide-react';
import { usePlayerStore } from '../store/playerStore';
import { getImageUrl, getAudioUrl } from '../services/api';
import { AnimatePresence, motion } from 'framer-motion';
import { DownloadQualityModal } from './DownloadQualityModal';
import { Song } from '../types';

export const Player: React.FC = () => {
  const { 
    currentSong, 
    isPlaying, 
    isBuffering,
    isFullScreen,
    setFullScreen,
    togglePlay, 
    setIsPlaying, 
    setIsBuffering,
    nextSong, 
    prevSong,
    queue,
    likedSongs,
    toggleLike,
    isShuffling,
    streamingQuality
  } = usePlayerStore();

  const audioRef = useRef<HTMLAudioElement>(null);
  const [progress, setProgress] = useState(0);
  const [duration, setDuration] = useState(0);
  const [downloadSong, setDownloadSong] = useState<Song | null>(null);

  const isLiked = currentSong ? likedSongs.some(s => s.id === currentSong.id) : false;

  useEffect(() => {
    if (!currentSong || !audioRef.current) return;
    const url = getAudioUrl(currentSong.downloadUrl, streamingQuality);
    if (audioRef.current.src !== url) {
        const wasPlaying = isPlaying;
        audioRef.current.src = url;
        audioRef.current.load();
        if (wasPlaying) {
             const playPromise = audioRef.current.play();
             if (playPromise !== undefined) {
                 playPromise.catch(() => setIsPlaying(false));
             }
        }
    }
  }, [currentSong?.id, streamingQuality]);

  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;
    if (isPlaying && audio.paused) audio.play().catch(() => {});
    else if (!isPlaying && !audio.paused) audio.pause();
  }, [isPlaying]);

  const handleTimeUpdate = () => {
    if (audioRef.current) {
      setProgress(audioRef.current.currentTime);
      setDuration(audioRef.current.duration || 0);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const time = parseFloat(e.target.value);
    setProgress(time);
    if (audioRef.current) audioRef.current.currentTime = time;
  };

  const formatTime = (seconds: number) => {
    if (!seconds || isNaN(seconds)) return "00:00";
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  if (!currentSong) return null;

  const imageUrl = getImageUrl(currentSong.image);
  const primaryArtistName = currentSong.artists?.primary?.[0]?.name || "Unknown Unit";
  const percent = (progress / (duration || 1)) * 100;

  return (
    <>
        <audio 
            ref={audioRef}
            preload="auto"
            onTimeUpdate={handleTimeUpdate}
            onEnded={nextSong}
            onWaiting={() => setIsBuffering(true)}
            onPlaying={() => setIsBuffering(false)}
        />

        <AnimatePresence>
        {isFullScreen && (
        <motion.div 
            initial={{ y: "100%" }}
            animate={{ y: 0 }}
            exit={{ y: "100%" }}
            transition={{ type: "spring", damping: 20, stiffness: 100 }}
            className="fixed inset-0 z-[200] flex flex-col bg-[#050505] overflow-hidden font-sans"
        >
            {/* Tech Background */}
            <div className="absolute inset-0 pointer-events-none">
                <div className="absolute inset-0 bg-carbon opacity-50"></div>
                <div className="absolute inset-0 bg-[linear-gradient(rgba(255,0,60,0.03)_1px,transparent_1px),linear-gradient(90deg,rgba(255,0,60,0.03)_1px,transparent_1px)] bg-[size:50px_50px]"></div>
                <div className="absolute top-0 left-0 w-full h-32 bg-gradient-to-b from-accent/10 to-transparent"></div>
            </div>

            {/* Header */}
            <div className="relative z-10 flex items-center justify-between px-6 pt-6 mb-4">
                <button onClick={() => setFullScreen(false)} className="text-white hover:text-accent transition-colors">
                    <Minimize2 size={24} />
                </button>
                <div className="flex flex-col items-center">
                    <span className="text-[10px] font-mono text-accent tracking-[0.3em] uppercase animate-pulse">System.Audio.Output</span>
                    <span className="text-xs font-bold text-white uppercase tracking-wider">Now Playing</span>
                </div>
                <button className="text-white hover:text-accent">
                    <MoreHorizontal size={24} />
                </button>
            </div>

            {/* Main Content */}
            <div className="relative z-10 flex-1 flex flex-col items-center justify-center p-6">

                 {/* Visualizer Ring (Static CSS) */}
                 <div className="relative w-[300px] h-[300px] md:w-[400px] md:h-[400px] flex items-center justify-center mb-10">
                    <div className="absolute inset-0 border border-white/10 rounded-full animate-[spin_10s_linear_infinite]"></div>
                    <div className="absolute inset-[-10px] border border-accent/20 rounded-full border-dashed animate-[spin_20s_linear_infinite_reverse]"></div>
                    <div className="absolute inset-0 rounded-full bg-accent/5 blur-3xl animate-pulse"></div>

                    <img 
                        src={imageUrl} 
                        alt="cover" 
                        className="w-[280px] h-[280px] md:w-[380px] md:h-[380px] object-cover clip-angle shadow-[0_0_30px_rgba(0,0,0,0.8)] grayscale-[20%] contrast-125 border-2 border-white/10"
                    />
                 </div>

                 <div className="w-full max-w-lg">
                    {/* Track Info */}
                    <div className="flex items-center justify-between mb-6 border-l-4 border-accent pl-4 bg-gradient-to-r from-white/5 to-transparent py-2">
                        <div className="overflow-hidden">
                            <h1 className="text-2xl md:text-4xl font-display font-bold text-white uppercase tracking-tight truncate">{currentSong.name}</h1>
                            <p className="text-secondary text-sm md:text-base font-mono uppercase tracking-widest truncate">{primaryArtistName}</p>
                        </div>
                        <button onClick={() => toggleLike(currentSong)} className="text-white hover:text-accent transition-colors">
                             {isLiked ? <Heart size={28} fill="#ff003c" className="text-accent drop-shadow-[0_0_10px_rgba(255,0,60,0.8)]" /> : <Heart size={28} />}
                        </button>
                    </div>

                    {/* Tech Scrubber */}
                    <div className="mb-8">
                        <div className="flex justify-between text-[10px] font-mono text-accent mb-1 px-1">
                             <span>T-{formatTime(progress)}</span>
                             <span>LEN-{formatTime(duration)}</span>
                        </div>
                        <div className="relative h-2 w-full bg-[#1a1a1a] clip-angle-sm">
                             <div 
                                className="absolute top-0 left-0 h-full bg-accent shadow-[0_0_15px_#ff003c]"
                                style={{ width: `${percent}%` }}
                             ></div>
                             {/* Striped overlay */}
                             <div className="absolute inset-0 bg-[repeating-linear-gradient(90deg,transparent,transparent_2px,#000_2px,#000_4px)] opacity-30"></div>

                             <input 
                                type="range" 
                                min="0" 
                                max={duration || 100} 
                                value={progress}
                                onChange={handleSeek}
                                className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                            />
                        </div>
                    </div>

                    {/* Controls */}
                    <div className="flex items-center justify-between px-4">
                        <button className={`hover:text-white transition-colors ${isShuffling ? 'text-accent' : 'text-white/30'}`}>
                            <Shuffle size={20} />
                        </button>

                        <div className="flex items-center gap-8">
                            <button onClick={prevSong} className="text-white hover:text-accent transition-colors active:scale-90">
                                <SkipBack size={32} fill="currentColor" />
                            </button>

                            <button 
                                onClick={togglePlay}
                                className="w-20 h-20 bg-accent text-white clip-angle flex items-center justify-center hover:bg-[#d10024] active:scale-95 transition-all shadow-[0_0_20px_rgba(255,0,60,0.4)] border border-white/20"
                            >
                                {isBuffering ? (
                                    <Loader2 size={32} className="animate-spin" />
                                ) : isPlaying ? (
                                    <Pause size={32} fill="white" />
                                ) : (
                                    <Play size={32} fill="white" className="ml-1" />
                                )}
                            </button>

                            <button onClick={nextSong} className="text-white hover:text-accent transition-colors active:scale-90">
                                <SkipForward size={32} fill="currentColor" />
                            </button>
                        </div>

                        <button className="text-white/30 hover:text-white transition-colors">
                            <Repeat size={20} />
                        </button>
                    </div>
                 </div>
            </div>

            {/* Footer Data */}
            <div className="p-6 flex justify-between items-center text-[#333] font-mono text-xs uppercase tracking-widest border-t border-white/5">
                <span>Bitrate: {streamingQuality === 'high' ? '320' : '128'} KBPS</span>
                <span>SECURE_CONNECTION: TRUE</span>
            </div>
        </motion.div>
        )}
        </AnimatePresence>

        {/* --- MINI PLAYER (HUD STRIP) --- */}
        <AnimatePresence>
        {!isFullScreen && (
            <motion.div 
                initial={{ y: 20, opacity: 0 }}
                animate={{ y: 0, opacity: 1 }}
                exit={{ y: 20, opacity: 0 }}
                onClick={() => setFullScreen(true)}
                className="fixed bottom-[60px] md:bottom-2 left-2 right-2 md:left-[330px] md:right-4 h-[64px] bg-[#111] border-l-4 border-accent clip-angle-sm flex items-center pr-4 shadow-[0_0_20px_rgba(0,0,0,0.8)] z-[150] cursor-pointer group"
            >
                {/* Tech Lines */}
                <div className="absolute top-1 right-2 flex gap-1">
                    <div className="w-8 h-1 bg-white/10 skew-x-[-45deg]"></div>
                    <div className="w-2 h-1 bg-accent skew-x-[-45deg]"></div>
                </div>

                <div className="relative h-16 w-16 -ml-1 mr-4 shrink-0">
                   <img src={imageUrl} alt="cover" className="h-full w-full object-cover opacity-80 group-hover:opacity-100 transition-opacity" />
                   {/* Scanline overlay on image */}
                   <div className="absolute inset-0 bg-[linear-gradient(rgba(0,0,0,0.5)_1px,transparent_1px)] bg-[size:100%_4px]"></div>
                </div>

                <div className="flex-1 min-w-0 flex flex-col justify-center">
                     <span className="text-white font-display font-bold text-sm tracking-wide truncate uppercase">{currentSong.name}</span>
                     <div className="flex items-center gap-2">
                         <span className="text-accent text-[10px] font-mono uppercase">{primaryArtistName}</span>
                         {isBuffering && <span className="text-white/50 text-[9px] animate-pulse"> LOADING_DATA...</span>}
                     </div>
                </div>

                <div className="flex items-center gap-4">
                     <button onClick={(e) => { e.stopPropagation(); toggleLike(currentSong); }} className="text-white/30 hover:text-accent transition-colors hidden sm:block">
                        <Heart size={18} fill={isLiked ? "#ff003c" : "transparent"} />
                     </button>
                     <button 
                        onClick={(e) => { e.stopPropagation(); togglePlay(); }} 
                        className="w-10 h-10 bg-white/5 hover:bg-white/10 border border-white/10 flex items-center justify-center clip-angle-sm transition-all hover:text-accent"
                    >
                        {isBuffering ? <Loader2 size={18} className="animate-spin" /> : isPlaying ? <Pause size={18} fill="currentColor" /> : <Play size={18} fill="currentColor" />}
                     </button>
                </div>

                {/* Progress Strip Bottom */}
                <div className="absolute bottom-0 left-0 right-0 h-[2px] bg-[#000]">
                     <div 
                        className="h-full bg-accent shadow-[0_0_10px_#ff003c]" 
                        style={{ width: `${percent}%` }}
