export const Home: React.FC = () => {
  const [daylist, setDaylist] = useState<Song[]>([]);
  const [recent, setRecent] = useState<(Song | Album)[]>([]); 
  const { history, playSong, currentUser } = usePlayerStore();
  const navigate = useNavigate();
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      setIsLoading(true);
      try {
        const songs = await api.searchSongs('Gaming Music High Energy');
        await new Promise(r => setTimeout(r, 400));
        setDaylist(songs);
      } catch (e) { console.error(e); } 
      finally { setIsLoading(false); }
    };
    fetchData();
  }, []);

  useEffect(() => {
    if (history.length > 0) setRecent(history.slice(0, 6));
    else {
       Promise.all([
         api.searchSongs("Cyberpunk 2077"),
         api.searchAlbums("Tron Legacy"),
         api.searchSongs("Daft Punk"),
       ]).then(([songs, albums, songs2]) => {
          setRecent([...songs.slice(0,2), ...albums.slice(0,2), ...songs2.slice(0,2)]);
       });
    }
  }, [history]);

  const SectionTitle = ({ title }: { title: string }) => (
      <div className="flex items-center gap-2 mb-4 px-4">
        <div className="w-1 h-6 bg-accent"></div>
        <h2 className="text-xl md:text-2xl font-display font-bold text-white tracking-widest uppercase hover:text-accent transition-colors cursor-default">{title}</h2>
        <div className="h-[1px] flex-1 bg-white/10 ml-2"></div>
      </div>
  );

  return (
    <div className="flex flex-col gap-8 pb-36 relative min-h-full">

      {/* HUD Header */}
      <div className="px-6 pt-6 flex items-center justify-between sticky top-0 z-40 bg-background/80 backdrop-blur-md border-b border-white/5 pb-4">
         <div className="flex items-center gap-3">
             <div 
                onClick={() => currentUser ? navigate('/profile') : navigate('/login')}
                className="w-10 h-10 clip-angle-sm bg-white/5 border border-white/10 flex items-center justify-center cursor-pointer hover:border-accent hover:bg-accent/10 transition-all group"
             >
                 {currentUser && currentUser.image ? (
                     <img src={currentUser.image} alt="Profile" className="w-full h-full object-cover grayscale group-hover:grayscale-0" />
                 ) : (
                     <UserCircle size={24} className="text-white group-hover:text-accent" />
                 )}
             </div>
             <div className="flex flex-col">
                 <span className="text-[10px] text-accent font-mono uppercase tracking-wider">Operator</span>
                 <span className="text-sm font-bold text-white uppercase">{currentUser ? currentUser.name : 'GUEST_USER'}</span>
             </div>
         </div>

         <div className="flex gap-2">
             <button className="px-4 py-1.5 border border-accent/50 text-accent text-xs font-bold uppercase tracking-wider hover:bg-accent hover:text-black transition-all clip-angle-sm">ALL_SYSTEMS</button>
             <button className="px-4 py-1.5 border border-white/10 text-secondary text-xs font-bold uppercase tracking-wider hover:bg-white/10 transition-all clip-angle-sm">MUSIC</button>
         </div>
      </div>

      {/* Hero / Shortcuts */}
      <div className="px-4">
          <SectionTitle title="Quick_Access" />
          <div className="grid grid-cols-2 lg:grid-cols-3 gap-3">
            <div 
                onClick={() => navigate('/liked')}
                className="flex items-center gap-3 bg-[#111] hover:bg-[#1a1a1a] p-2 border border-white/5 hover:border-accent/50 clip-angle-sm cursor-pointer transition-all group"
            >
                <div className="w-12 h-12 bg-gradient-to-br from-accent to-black flex items-center justify-center shrink-0 clip-angle-sm">
                    <Zap size={20} className="text-white" />
                </div>
                <span className="font-bold text-sm text-white uppercase tracking-wider group-hover:text-accent group-hover:glitch">LIKED_SONGS</span>
            </div>

            {recent.slice(0, 5).map((item, idx) => (
                <div 
                    key={idx}
                    onClick={() => item.type === 'song' ? playSong(item as Song, [item as Song]) : navigate(`/album/${item.id}`)}
                    className="flex items-center gap-3 bg-[#111] hover:bg-[#1a1a1a] p-2 border border-white/5 hover:border-accent/50 clip-angle-sm cursor-pointer transition-all group"
                >
                    <img src={getImageUrl(item.image)} className="w-12 h-12 object-cover clip-angle-sm grayscale group-hover:grayscale-0 transition-all" alt=""/>
                    <span className="font-bold text-sm text-white uppercase tracking-wider truncate pr-2 group-hover:text-accent">{item.name}</span>
                </div>
            ))}
          </div>
      </div>

      {/* Sections */}
      <section>
        <SectionTitle title="Recommended_Stream" />
        <div className="flex overflow-x-auto gap-4 pb-4 no-scrollbar px-4 snap-x">
            {isLoading ? Array(6).fill(0).map((_, i) => <SkeletonCard key={i} />) : 
                 daylist.map((item, i) => (
                    <div key={i} className="snap-start">
                        <SongCard item={item} onPlay={() => playSong(item, daylist)} />
                    </div>
                 ))
            }
        </div>
      </section>

      <section>
        <SectionTitle title="Recent_Data_Logs" />
        <div className="flex overflow-x-auto gap-4 pb-4 no-scrollbar px-4 snap-x">
            {isLoading ? Array(4).fill(0).map((_, i) => <SkeletonCard key={i} />) : 
                recent.map((item, i) => (
                    <div key={i} className="snap-start">
                        <SongCard item={item} onPlay={() => item.type === 'song' && playSong(item as Song, [item as Song])} />
                    </div>
                ))
            }
        </div>
      </section>

      {/* Decorative Footer */}
      <div className="px-4 py-8 border-t border-white/5 mt-4 opacity-50">
          <div className="flex items-center gap-2 text-[10px] font-mono text-secondary uppercase">
             <Terminal size={12} />
             <span>System Status: Optimal // VibeStream.OS v2.4 // </span>
             <span className="animate-pulse text-accent"> CONNECTED</span>
          </div>
      </div>
    </div>
  );
